import {IonIcon} from '@ionic/react';
import Link, {ThLink} from '../../components/Link';
import ScrollContainer from '../../components/ScrollContainer';
import InnerLink from '../../components/InnerLink';
const _produce_flame = {title: "Produce Flame", jsx: <><h2 id="spell-produce_flame-produce-flame">Produce Flame</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 326</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link> [<Link to="/spelldef/fire">fire</Link>]; <strong>Level</strong> druid 1, hunter 1, shaman 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> 0 ft.<br/><strong>Effect</strong> flame in your palm<br/><strong>Duration</strong> 1 minute/level (D)<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> yes</p><p>Flames as bright as a torch appear in your open hand. The flames harm neither you nor your equipment.</p>
<p>In addition to providing illumination, the flames can be hurled or used to touch enemies. You can strike an opponent with a melee touch attack, dealing fire damage equal to 1d6 + 1 point per caster level (maximum +5). Alternatively, you can hurl the flames up to 120 feet as a thrown weapon. When doing so, you attack with a ranged touch attack (with no range penalty) and deal the same damage as with the melee attack. No sooner do you hurl the flames than a new set appears in your hand. Each attack you make reduces the remaining duration by 1 minute. If an attack reduces the remaining duration to 0 minutes or less, the spell ends after the attack resolves.</p>
<p>This spell does not function underwater.</p>
<h3 id="spell-produce_flame-pale-flame">Pale Flame</h3>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_darklands">Heroes of the Darklands pg. 15</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link> [<Link to="/spelldef/fire">fire</Link>]; <strong>Level</strong> druid 2, hunter 2, shaman 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (caphorite shard)<br/><strong>Range</strong> 0 ft.<br/><strong>Effect</strong> flame in your palm<br/><strong>Duration</strong> 1 minute/level (D)<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> yes</p><p>This spell functions as per produce flame, except that the flames never glow brighter than dim light, including any fires started by this spell. These flames cast light only half the distance of a torch and cannot be seen from more than 100 feet away. The flames deal 2d6 points of fire damage + 1 point per caster level (maximum +5). Against plants, this damage increases to 2d6 points + 2 points per caster level (maximum +10).</p>
</>};
const _profane_nimbus = {title: "Profane Nimbus", jsx: <><h2 id="spell-profane_nimbus-profane-nimbus">Profane Nimbus</h2>
<p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 125</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link> [<Link to="/spelldef/evil">evil</Link>]; <strong>Level</strong> antipaladin 4, cleric 5, inquisitor 5, oracle 5, warpriest 5<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 round/level (D)</p><p>You are surrounded by a nimbus of shadow shaped like your god's unholy symbol or a symbol of your faith. Any good creature striking you with unarmed strikes, natural weapons, or a handheld weapon deals normal damage, but at the same time, the attacker takes 1d6 points of damage + 1 point per caster level (maximum +15). Creatures wielding melee weapons with reach are not subject to this damage if they attack you. Spell resistance applies against this damage. You also take half damage from magical attacks with the good descriptor. If such an attack allows a Reflex save for half damage, you take no damage on a successful saving throw.</p>
</>};
const _programmed_image = {title: "Programmed Image", jsx: <><h2 id="spell-programmed_image-programmed-image">Programmed Image</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 327</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/figment">figment</Link>); <strong>Level</strong> arcanist 6, bard 6, mesmerist 6, psychic 6, skald 6, sorcerer 6, wizard 6<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (fleece and jade dust worth 25 gp)<br/><strong>Range</strong> long (400 ft. + 40 ft./level)<br/><strong>Effect</strong> visual figment that cannot extend beyond a 20-ft. cube + one 10-ft. cube/level (S)<br/><strong>Duration</strong> permanent until triggered, then 1 round/level<br/><strong>Saving Throw</strong> Will disbelief (if interacted with); <strong>Spell Resistance</strong> no</p><p>This spell functions like silent image, except that this spell's figment activates when a specific condition occurs. The figment includes visual, auditory, olfactory, and thermal elements, including intelligible speech.</p>
<p>You set the triggering condition (which may be a special word) when casting the spell. The event that triggers the illusion can be as general or as specific and detailed as desired but must be based on an audible, tactile, olfactory, or visual trigger. The trigger cannot be based on some quality not normally obvious to the senses, such as alignment. See magic mouth for more details about such triggers.</p>
</>};
const _project_image = {title: "Project Image", jsx: <><h2 id="spell-project_image-project-image">Project Image</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 327</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/shadow_subschool">_subschool</Link>) [<Link to="/spelldef/shadow_descriptor">_descriptor</Link>]; <strong>Level</strong> arcanist 7, bard 6, mesmerist 6, occultist 6, psychic 7, skald 6, sorcerer 7, wizard 7<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a small replica of you worth 5 gp)<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Effect</strong> one shadow duplicate<br/><strong>Duration</strong> 1 round/level (D)<br/><strong>Saving Throw</strong> Will disbelief (if interacted with); <strong>Spell Resistance</strong> no</p><p>You tap energy from the Plane of Shadow to create a quasi-real, illusory version of yourself. The projected image looks, sounds, and smells like you but is intangible. The projected image mimics your actions (including speech) unless you direct it to act differently (which is a move action).</p>
<p>You can see through its eyes and hear through its ears as if you were standing where it is, and during your turn you can switch from using its senses to using your own, or back again, as a free action. While you are using its senses, your body is considered blinded and deafened.</p>
<p>If you desire, any spell you cast whose range is touch or greater can originate from the projected image instead of from you. The projected image can't cast any spells on itself except for illusion spells. The spells affect other targets normally, despite originating from the projected image.</p>
<p>Objects are affected by the projected image as if they had succeeded on their Will save. You must maintain line of effect to the projected image at all times. If your line of effect is obstructed, the spell ends. If you use <Link to="/spell/dimension_door">dimension door</Link>, <Link to="/spell/teleport">teleport</Link>, <Link to="/spell/plane_shift">plane shift</Link>, or a similar spell that breaks your line of effect, even momentarily, the spell ends.</p>
<h3 id="spell-project_image-familiar-double">Familiar Double</h3>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 181</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/shadow_subschool">_subschool</Link>); <strong>Level</strong> witch 7<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a small replica of you worth 5 gp)<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Effect</strong> one shadow duplicate<br/><strong>Duration</strong> 1 round/level (D)<br/><strong>Saving Throw</strong> Will disbelief (if interacted with); <strong>Spell Resistance</strong> no</p><p>This spell functions as project image, except the image appears in your familiar's square and moves when your familiar moves.</p>
</>};
const _project_weakness = {title: "Project Weakness", jsx: <><h2 id="spell-project_weakness-project-weakness">Project Weakness</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_night">Blood of the Night pg. 30</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link> [<Link to="/spelldef/curse">curse</Link>, <Link to="/spelldef/evil">evil</Link>]; <strong>Level</strong> arcanist 4, cleric 3, oracle 3, sorcerer 4, warpriest 3, witch 3, wizard 4<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> touch<br/><strong>Target</strong> living creature touched<br/><strong>Duration</strong> permanent<br/><strong>Saving Throw</strong> Will negates; <strong>Spell Resistance</strong> yes</p><blockquote>
<p><em><Link to="/template/vampire">Vampires</Link> have access to the following spell.</em></p>
</blockquote>
<p>You curse the target with the weaknesses of your kind of vampirism. The creature reacts to garlic, mirrors, ringing bells, sunlight, and so on as if it were a vampire of the same type as you. This cannot kill the target; anything that would kill it (such as a lengthy exposure to sunlight if you are a moroi vampire) renders it helpless until the curse or the harmful effect is removed. The target gains none of the benefits of being a vampire (such as fast healing or requiring special ways to be permanently killed), only the penalties.</p>
</>};
const _prophetic_lore = {title: "Prophetic Lore", jsx: <><h2 id="spell-prophetic_lore-prophetic-lore">Prophetic Lore</h2>
<p><strong>Sources</strong> <Link to="/source/disciples_doctrine">Disciple's Doctrine pg. 11</Link><br/><strong>School</strong> <Link to="/spelldef/divination">divination</Link>; <strong>Level</strong> arcanist 6, sorcerer 6, wizard 6<br/><strong>Casting Time</strong> see below<br/><strong>Components</strong> V, S, M (incense worth 150 gp), F (rare herbs and spices worth 250 gp)<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> see text</p><p>You call to mind prophecies regarding a person, place, item, or event. These might be predictions made in the past, lost to history, or entirely new. If the person or item is present or if you are at the desired location, the casting time is 1d4&times;10 minutes; if you have general but specific information about the subject, the casting time is 1d4&times;2 hours. If you have only rumors, you cannot cast this spell with any effect.</p>
<p>More than one prophecy can come to mind when you cast this spell, and each are of varying detail and accuracy. Roll d% and add your caster level (maximum 10) to determine results this spell returns, as listed below.</p>
<ScrollContainer id="spell-prophetic_lore--table-0"><table>
<thead>
<tr>
<th>d%</th>
<th>Result</th>
</tr>
</thead>
<tbody><tr>
<td>01-25</td>
<td>Your prophecy is vague, difficult to interpret, or does not offer any new subjects for further investigation.</td>
</tr>
<tr>
<td>26-50</td>
<td>You divine multiple prophecies for the subject, but you are unsure which applies. You have enough information to gain a +5 bonus on Knowledge, Perception, and Sense Motive checks about the subject. If you discover more information about the subject using these skills, you gain a +10 bonus when rolling on this table the next time you cast this spell within 24 hours. You can gain this bonus only once in a single 24-hour period.</td>
</tr>
<tr>
<td>51-75</td>
<td>You identify multiple prophecies and know which single prophecy is most likely to take effect and which is most likely to be false or fraudulent. If no prophecy is accurate, you become aware of this. Even accurate prophecies are often vague, and how easy it is to determine details from one is up to the GM.</td>
</tr>
<tr>
<td>76-100</td>
<td>You gain accurate visions of a single prophecy regarding the subject. You know what this prophecy means and what it foretells, it is generally accurate, and it comes in the form of a single statement, though the timeline for when the prophecy will come true might be vague. (For example, "Flames shall consume it within a month" if the subject is a tavern destined to burn, or "The murderer shall be discovered by a hero" if the subject is a murder victim.)</td>
</tr>
</tbody></table></ScrollContainer>
</>};
const _prosperous_room = {title: "Prosperous Room", jsx: <><h2 id="spell-prosperous_room-prosperous-room">Prosperous Room</h2>
<p><strong>Sources</strong> <Link to="/source/quests_and_campaigns">Quests and Campaigns pg. 29</Link><br/><strong>School</strong> <Link to="/spelldef/enchantment">enchantment</Link>; <strong>Level</strong> arcanist 3, bard 3, skald 3, sorcerer 3, wizard 3<br/><strong>Casting Time</strong> 1 day<br/><strong>Components</strong> V, S<br/><strong>Range</strong> touch<br/><strong>Target</strong> room you own; see text<br/><strong>Duration</strong> 1 day/level (D)<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> yes</p><p>The targeted room is enchanted to have magical appeal for customers, an increase in the workflow of its employees, or the generation of additional materials to work with. While this spell is in effect, the targeted room produces 1 more Goods, Labor, Influence, or Magic than it already does. If the room produces multiple types of capital, it produces an additional capital of each type. If the room generates gp, it generates 25% more. Only the capital that the room normally generates increases-rooms that do not already generate Magic, for instance, do not generate Magic because of this spell.</p>
<p>While this spell is in effect, neither you nor your allies can further interact with the affected room or the spell's effects immediately end. You cannot spend downtime actions to run a business with a room that is affected by this spell, though any employees or workers that operate within the room may continue to do so normally.</p>
</>};
const _protection_from_arrows = {hasJL:true,title: "Protection from Arrows", jsx: <><div className="jumpList" id="spell-protection_from_arrows-jumplist"><h2>Jump to:</h2><ul><li><InnerLink toTop to="spell-protection_from_arrows-mythic_protection_from_arrows">Mythic Protection from Arrows</InnerLink></li><li><InnerLink toTop to="spell-protection_from_arrows-communal-protection-from-arrows">Communal Protection from Arrows</InnerLink></li></ul></div><h2 id="spell-protection_from_arrows-protection-from-arrows">Protection from Arrows</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 327</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link>; <strong>Level</strong> alchemist 2, arcanist 2, bloodrager 2, investigator 2, psychic 2, sorcerer 2, spiritualist 2, summoner 2, unchained summoner 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, F (a piece of tortoiseshell or turtle shell)<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> 1 hour/level or until discharged<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>The warded creature gains resistance to ranged weapons. The subject gains damage reduction 10/magic against ranged weapons. This spell doesn't grant you the ability to damage creatures with similar damage reduction. Once the spell has prevented a total of 10 points of damage per caster level (maximum 100 points), it is discharged.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="spell-protection_from_arrows--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col" id="spell-protection_from_arrows-mythic_protection_from_arrows" data-hash-target>Mythic Protection from Arrows</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 104</Link></p>
<p>The damage reduction increases to 15/magic. The maximum damage prevented by the spell increases to 15 points per caster level (maximum 150 points). If the spell prevents all damage from a ranged weapon attack, it turns the projectile or weapon back on the attacker, using the same attack roll result. If the attacker is also protected by mythic protection from arrows and its spell completely prevents the damage from the rebounded attack, the weapon or projectile is destroyed.</p>
</td></tr></tbody></table></ScrollContainer></div><h3 id="spell-protection_from_arrows-communal-protection-from-arrows" data-hash-target>Communal Protection from Arrows</h3>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 240</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link>; <strong>Level</strong> alchemist 3, arcanist 3, investigator 3, psychic 3, sorcerer 3, summoner 3, unchained summoner 3, wizard 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, F (a piece of tortoiseshell or turtle shell)<br/><strong>Range</strong> touch<br/><strong>Targets</strong> creatures touched<br/><strong>Duration</strong> 1 hour/level or until discharged<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>This spell functions like protection from arrows, except you divide the duration in 1-hour intervals among the creatures touched. Once the spell absorbs 10 points of damage per caster level (maximum 100 points) for a subject, the spell's effects end for that subject.</p>
</>};
const _protection_from_energy = {title: "Protection from Energy", jsx: <><h2 id="spell-protection_from_energy-protection-from-energy">Protection from Energy</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 327</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link>; <strong>Level</strong> alchemist 3, arcanist 3, bloodrager 3, cleric 3, druid 3, hunter 2, inquisitor 3, investigator 3, occultist 3, oracle 3, psychic 3, ranger 2, shaman 3, sorcerer 3, spiritualist 3, summoner 3, unchained summoner 3, warpriest 3, wizard 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> 10 min./level or until discharged<br/><strong>Saving Throw</strong> Fortitude negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>Protection from energy grants temporary immunity to the type of energy you specify when you cast it (acid, cold, electricity, fire, or sonic). When the spell absorbs 12 points per caster level of energy damage (to a maximum of 120 points at 10th level), it is discharged.</p>
<p>Protection from energy overlaps (and does not stack with) <Link to="/spell/resist_energy">resist energy</Link>. If a character is warded by protection from energy and resist energy, the protection spell absorbs damage until its power is exhausted.</p>
<h3 id="spell-protection_from_energy-communal-protection-from-energy">Communal Protection from Energy</h3>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 240</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link>; <strong>Level</strong> arcanist 4, cleric 4, druid 4, hunter 3, inquisitor 4, oracle 4, psychic 4, ranger 3, sorcerer 4, summoner 4, unchained summoner 4, warpriest 4, wizard 4<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> touch<br/><strong>Targets</strong> creatures touched<br/><strong>Duration</strong> 10 min./level or until discharged<br/><strong>Saving Throw</strong> Fortitude negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>This spell functions like protection from energy, except you divide the duration in 10-minute intervals among the creatures touched. Once the spell absorbs 12 points of energy damage per caster level (maximum 120 points) for a subject, the spell's effects end for that subject.</p>
</>};
const _protection_from_evil = {hasJL:true,title: "Protection from Evil", jsx: <><div className="jumpList" id="spell-protection_from_evil-jumplist"><h2>Jump to:</h2><ul><li><InnerLink toTop to="spell-protection_from_evil-mythic_protection_from_evil">Mythic Protection from Evil</InnerLink></li><li><InnerLink toTop to="spell-protection_from_evil-communal-protection-from-evil">Communal Protection from Evil</InnerLink></li><li><InnerLink toTop to="spell-protection_from_evil-protection-from-chaos">Protection from Chaos</InnerLink></li><li><InnerLink toTop to="spell-protection_from_evil-mythic_protection_from_chaos">Mythic Protection from Chaos</InnerLink></li><li><InnerLink toTop to="spell-protection_from_evil-communal-protection-from-chaos">Communal Protection from Chaos</InnerLink></li><li><InnerLink toTop to="spell-protection_from_evil-protection-from-good">Protection from Good</InnerLink></li><li><InnerLink toTop to="spell-protection_from_evil-mythic_protection_from_good">Mythic Protection from Good</InnerLink></li><li><InnerLink toTop to="spell-protection_from_evil-communal-protection-from-good">Communal Protection from Good</InnerLink></li><li><InnerLink toTop to="spell-protection_from_evil-protection-from-law">Protection from Law</InnerLink></li><li><InnerLink toTop to="spell-protection_from_evil-mythic_protection_from_law">Mythic Protection from Law</InnerLink></li><li><InnerLink toTop to="spell-protection_from_evil-communal-protection-from-law">Communal Protection from Law</InnerLink></li></ul></div><h2 id="spell-protection_from_evil-protection-from-evil">Protection from Evil</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 327</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link> [<Link to="/spelldef/good">good</Link>]; <strong>Level</strong> adept 1, arcanist 1, bloodrager 1, cleric 1, inquisitor 1, medium 1, oracle 1, paladin 1, shaman 1, sorcerer 1, spiritualist 1, summoner 1, unchained summoner 1, warpriest 1, wizard 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M/DF<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> 1 minute/level (D)<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> no; see text</p><p>This spell wards a creature from attacks by evil creatures, from mental control, and from summoned creatures. It creates a magical barrier around the subject at a distance of 1 foot. The barrier moves with the subject and has three major effects.</p>
<p>First, the subject gains a +2 deflection bonus to AC and a +2 resistance bonus on saves. Both these bonuses apply against attacks made or effects created by evil creatures.</p>
<p>Second, the subject immediately receives another saving throw (if one was allowed to begin with) against any spells or effects that possess or exercise mental control over the creature (including enchantment [charm] effects and enchantment [compulsion] effects, such as charm person, command, and dominate person. This saving throw is made with a +2 morale bonus, using the same DC as the original effect. If successful, such effects are suppressed for the duration of this spell. The effects resume when the duration of this spell expires. While under the effects of this spell, the target is immune to any new attempts to possess or exercise mental control over the target. This spell does not expel a controlling life force (such as a <Link to="/template/ghost">ghost</Link> or spellcaster using <Link to="/spell/magic_jar">magic jar</Link>), but it does prevent them from controlling the target. This second effect only functions against spells and effects created by evil creatures or objects, subject to GM discretion.</p>
<p>Third, the spell prevents bodily contact by evil summoned creatures. This causes the natural weapon attacks of such creatures to fail and the creatures to recoil if such attacks require touching the warded creature. Summoned creatures that are not evil are immune to this effect. The protection against contact by summoned creatures ends if the warded creature makes an attack against or tries to force the barrier against the blocked creature. Spell resistance can allow a creature to overcome this protection and touch the warded creature.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="spell-protection_from_evil--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col" id="spell-protection_from_evil-mythic_protection_from_evil" data-hash-target>Mythic Protection from Evil</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 105</Link></p>
<p>The bonuses to AC and on saves increase to +4. Any evil creature attempting to possess or exercise mental control over the target must attempt a Will save against this spell. If it fails, the creature takes 1d6 points of damage per 2 caster levels (maximum 5d6) from mental feedback. An evil creature that uses spell resistance to bypass the spell's protection against contact must successfully save or take this damage once each round it attacks the protected target.</p>
</td></tr></tbody></table></ScrollContainer></div><h3 id="spell-protection_from_evil-communal-protection-from-evil" data-hash-target>Communal Protection from Evil</h3>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 240</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link> [<Link to="/spelldef/good">good</Link>]; <strong>Level</strong> arcanist 2, cleric 2, inquisitor 2, oracle 2, paladin 2, sorcerer 2, summoner 2, unchained summoner 2, warpriest 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M/DF<br/><strong>Range</strong> touch<br/><strong>Targets</strong> creatures touched<br/><strong>Duration</strong> 1 minute/level (D)<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> no; see text</p><p>This spell functions like <em>protection from evil,</em> except you divide the duration in 1-minute intervals among the creatures touched.</p>
<h3 id="spell-protection_from_evil-protection-from-chaos" data-hash-target>Protection from Chaos</h3>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 327</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link> [<Link to="/spelldef/lawful">lawful</Link>]; <strong>Level</strong> adept 1, arcanist 1, bloodrager 1, cleric 1, inquisitor 1, medium 1, oracle 1, paladin 1, shaman 1, sorcerer 1, spiritualist 1, summoner 1, unchained summoner 1, warpriest 1, wizard 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M/DF<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> 1 minute/level (D)<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> no; see text</p><p>This spell functions like <em>protection from evil,</em> except that the deflection and resistance bonuses apply to attacks made by chaotic creatures. The target receives a new saving throw against control by chaotic creatures and chaotic summoned creatures cannot touch the target.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="spell-protection_from_evil--table-1"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col" id="spell-protection_from_evil-mythic_protection_from_chaos" data-hash-target>Mythic Protection from Chaos</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 104</Link></p>
<p>As mythic protection from evil, except against chaotic creatures.</p>
</td></tr></tbody></table></ScrollContainer></div><h3 id="spell-protection_from_evil-communal-protection-from-chaos" data-hash-target>Communal Protection from Chaos</h3>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 240</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link> [<Link to="/spelldef/lawful">lawful</Link>]; <strong>Level</strong> arcanist 2, cleric 2, inquisitor 2, oracle 2, paladin 2, sorcerer 2, summoner 2, unchained summoner 2, warpriest 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M/DF<br/><strong>Range</strong> touch<br/><strong>Targets</strong> creatures touched<br/><strong>Duration</strong> 1 minute/level (D)<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> no; see text</p><p>This spell functions like <em>communal protection from evil,</em> except it behaves like <em>protection from chaos</em> and you divide the duration in 1-minute intervals among the creatures touched.</p>
<h3 id="spell-protection_from_evil-protection-from-good" data-hash-target>Protection from Good</h3>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 328</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link> [<Link to="/spelldef/evil">evil</Link>]; <strong>Level</strong> adept 1, arcanist 1, bloodrager 1, cleric 1, inquisitor 1, medium 1, oracle 1, paladin 1, shaman 1, sorcerer 1, spiritualist 1, summoner 1, unchained summoner 1, warpriest 1, wizard 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M/DF<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> 1 minute/level (D)<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> no; see text</p><p>This spell functions like <em>protection from evil,</em> except that the deflection and resistance bonuses apply to attacks made by good creatures. The target receives a new saving throw against control by good creatures and good summoned creatures cannot touch the target.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="spell-protection_from_evil--table-2"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col" id="spell-protection_from_evil-mythic_protection_from_good" data-hash-target>Mythic Protection from Good</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 105</Link></p>
<p>As <em>mythic protection from evil,</em> except against good creatures.</p>
</td></tr></tbody></table></ScrollContainer></div><h3 id="spell-protection_from_evil-communal-protection-from-good" data-hash-target>Communal Protection from Good</h3>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 240</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link> [<Link to="/spelldef/evil">evil</Link>]; <strong>Level</strong> arcanist 2, cleric 2, inquisitor 2, oracle 2, paladin 2, sorcerer 2, summoner 2, unchained summoner 2, warpriest 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M/DF<br/><strong>Range</strong> touch<br/><strong>Targets</strong> creatures touched<br/><strong>Duration</strong> 1 minute/level (D)<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> no; see text</p><p>This spell functions like <em>communcal protection from evil,</em> except it behaves like <em>protection from good</em> and you divide the duration in 1-minute intervals among the creatures touched.</p>
<h3 id="spell-protection_from_evil-protection-from-law" data-hash-target>Protection from Law</h3>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 328</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link> [<Link to="/spelldef/chaotic">chaotic</Link>]; <strong>Level</strong> adept 1, arcanist 1, bloodrager 1, cleric 1, inquisitor 1, medium 1, oracle 1, paladin 1, shaman 1, sorcerer 1, spiritualist 1, summoner 1, unchained summoner 1, warpriest 1, wizard 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M/DF<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> 1 minute/level (D)<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> no; see text</p><p>This spell functions like <em>protection from evil,</em> except that the deflection and resistance bonuses apply to attacks made by lawful creatures. The target receives a new saving throw against control by lawful creatures and lawful summoned creatures cannot touch the target.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="spell-protection_from_evil--table-3"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col" id="spell-protection_from_evil-mythic_protection_from_law" data-hash-target>Mythic Protection from Law</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 105</Link></p>
<p>As <em>mythic protection from evil,</em> except against lawful creatures.</p>
</td></tr></tbody></table></ScrollContainer></div><h3 id="spell-protection_from_evil-communal-protection-from-law" data-hash-target>Communal Protection from Law</h3>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 240</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link> [<Link to="/spelldef/chaotic">chaotic</Link>]; <strong>Level</strong> arcanist 2, cleric 2, inquisitor 2, oracle 2, paladin 2, sorcerer 2, summoner 2, unchained summoner 2, warpriest 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M/DF<br/><strong>Range</strong> touch<br/><strong>Targets</strong> creatures touched<br/><strong>Duration</strong> 1 minute/level (D)<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> no; see text</p><p>This spell functions like <em>communal protection from evil,</em> except it behaves like <em>protection from law</em> and you divide the duration in 1-minute intervals among the creatures touched.</p>
</>};
const _protection_from_natural_attacks = {title: "Protection from Natural Attacks", jsx: <><h2 id="spell-protection_from_natural_attacks-protection-from-natural-attacks">Protection from Natural Attacks</h2>
<p><strong>Sources</strong> <Link to="/source/monster_hunters_handbook">Monster Hunter's Handbook pg. 30</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link>; <strong>Level</strong> alchemist 3, druid 4, hunter 2, investigator 3, psychic 4, ranger 2, shaman 4, spiritualist 3, summoner 3, unchained summoner 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M/DF (a scale from a lizard)<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> 1 minute/level<br/><strong>Saving Throw</strong> Fortitude negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>Upon casting this spell, select one type of natural attack from the following: bite, claw, gore, hoof, pincers, slam, sting, swarm, tail slap, talon, tentacle, or wing. For the duration of the spell, the target gains DR 5/- against all attacks from natural weapons of the selected type.</p>
</>};
const _protection_from_outsiders = {title: "Protection from Outsiders", jsx: <><h2 id="spell-protection_from_outsiders-protection-from-outsiders">Protection from Outsiders</h2>
<p><strong>Sources</strong> <Link to="/source/demon_hunters_handbook">Demon Hunter's Handbook pg. 26</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link> [see text]; <strong>Level</strong> cleric 2, inquisitor 2, oracle 2, paladin 2, warpriest 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> 1 minute/level (D)<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> no</p><p>This spell wards a creature from attacks by outsiders with a specific racial subtype, from mental control exerted by creatures of the chosen subtype, and from summoned creatures of that subtype. Only the subtypes of specific outsider races - angel, azata, demon, oni, psychopomp, protean, and so on - can be chosen as the subtype this spell protects against. Alignment subtypes or other general subtypes (like elemental, extraplanar, or native) cannot be selected. Outsiders without an outsider racial subtype (like genies, night hags, yeth hounds, or xills) are not affected by this spell.</p>
<p>This spell creates a magical barrier around the subject at a distance of 1 foot. The barrier moves with the subject and has three major effects.</p>
<p>First, the subject gains a +4 deflection bonus to AC and a +4 resistance bonus on saves when targeted by creatures of the chosen subtype.</p>
<p>Second, the subject immediately receives another saving throw (if one was allowed to begin with) against any spells or effects that possess or exercise mental control over the target creature. This functions in the same fashion as <Link to="/spell/protection_from_evil">protection from evil</Link>, but only when the effect stems from outsiders of the chosen subtype, and the target's saving throw is made with a +4 morale bonus (using the same DC as the original effect).</p>
<p>Third, the spell prevents bodily contact by summoned creatures of the chosen subtype in the same manner as detailed in protection from evil.</p>
<p>This spell's descriptor varies depending on the outsider race selected, gaining the alignment descriptors opposite to the alignment of the outsider race-for example, lawful and good if the race is chaotic and evil, chaotic if the selected race is lawful, or none if the selected race is neutral.</p>
</>};
const _protection_from_spells = {title: "Protection from Spells", jsx: <><h2 id="spell-protection_from_spells-protection-from-spells">Protection from Spells</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 328</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link>; <strong>Level</strong> arcanist 8, psychic 8, sorcerer 8, summoner 6, wizard 8<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (diamond worth 500 gp), F (One 1,000 gp diamond per target. Each subject must carry the gem for the duration of the spell. If a subject loses the gem, the spell ceases to affect him.)<br/><strong>Range</strong> touch<br/><strong>Targets</strong> up to one creature touched per four levels<br/><strong>Duration</strong> 10 minutes/level<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>The subject gains a +8 resistance bonus on saving throws against spells and spell-like abilities (but not against supernatural and extraordinary abilities).</p>
</>};
const _protection_from_spores = {title: "Protection from Spores", jsx: <><h2 id="spell-protection_from_spores-protection-from-spores">Protection from Spores</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_113_what_grows_within">Pathfinder #113: What Grows Within pg. 66</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link>; <strong>Level</strong> alchemist 2, cleric 2, druid 2, hunter 1, investigator 2, oracle 2, ranger 1, shaman 2, warpriest 2, witch 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> 1 minute/level<br/><strong>Saving Throw</strong> Fortitude negates (harmless); <strong>Spell Resistance</strong> no</p><blockquote>
<p><em>This spell is associated with <Link to="/faith/xhamen_dor">Xhamen-Dor</Link>, but there are no restrictions on its use by others.</em></p>
</blockquote>
<p>With a touch, you bolster a creature's body to protect it from the harmful effects of spores and similar afflictions. While under the effect of this spell, a creature is immune to the effects of brown mold, green slime, russet mold, yellow mold, and any similar hazard, provided the hazard is CR 6 or lower. Similarly, the creature is immune to poison, disease, and infestation attacks from all fungal creatures of CR 6 or lower, including effects such as basidirond spores, violet fungus rot, and the like. The target is immune to fungus-based toxins, such as striped toadstool. Against similar hazards or monsters of CR 7 or higher, the target gains a bonus on all saving throws against the effect equal to half your caster level. Protection from spores offers no protection against fungal infestations created by the seeded, by the spell what grows within, or by Xhamen-Dor.</p>
</>};
const _protection_from_technology = {title: "Protection from Technology", jsx: <><h2 id="spell-protection_from_technology-protection-from-technology">Protection from Technology</h2>
<p><strong>Sources</strong> <Link to="/source/technology_guide">Technology Guide pg. 10</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link>; <strong>Level</strong> arcanist 2, cleric 2, oracle 2, sorcerer 2, warpriest 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M/DF (a pinch of powdered copper)<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> 1 minute/level (D)<br/><strong>Saving Throw</strong> Will negates (harmless), see text; <strong>Spell Resistance</strong> no, see text</p><p>This spell wards a creature from attacks by technological objects and creatures of the robot subtype, and protects against mental control from technological sources. It creates a magical barrier around the subject at a distance of 1 foot. The barrier moves with the subject and has two major effects.</p>
<p>First, the target gains a +2 deflection bonus to AC and a +2 resistance bonus on saving throws. Both of these bonuses apply against attacks made or effects caused by technological objects and creatures with the robot subtype.</p>
<p>Second, the target immediately receives another saving throw (if one was allowed to begin with) against any technological effects that exercise mental control over the creature, including the effects of pharmaceuticals such as torpinal. The target gains a +2 morale bonus on this saving throw, using the same DC as the original effect. If the target succeeds at this save, such effects are suppressed for the duration of this spell. The effects resume when the duration of this spell expires. While under the effects of this spell, the target is immune to any new attempts to exercise mental control over her using technological means.</p>
</>};
const _protective_penumbra = {title: "Protective Penumbra", jsx: <><h2 id="spell-protective_penumbra-protective-penumbra">Protective Penumbra</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 233</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link> [<Link to="/spelldef/darkness">darkness</Link>]; <strong>Level</strong> arcanist 2, cleric 2, occultist 2, oracle 2, psychic 2, sorcerer 2, spiritualist 2, warpriest 2, witch 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> 10 minutes/level<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes</p><p>This spell keeps the target slightly in shadow. A target with light blindness, light sensitivity, or vulnerability to sunlight (such as vampires and wraiths) may ignore penalties from those qualities. The spell gives the target a +2 bonus on saving throws against nonmagical hazards related to bright light, such as glare or sunburn.</p>
</>};
const _protective_spirit = {title: "Protective Spirit", jsx: <><h2 id="spell-protective_spirit-protective-spirit">Protective Spirit</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 237</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/creation">creation</Link>); <strong>Level</strong> hunter 2, ranger 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 round/level</p><p>A protective spirit is an invisible, mindless, shapeless force that hovers about you, defending you against unexpected attacks. When a creature makes an attack of opportunity against you, the protective spirit makes an immediate attack using your base attack bonus plus your Dexterity modifier. On a successful hit, the spirit does no damage, but it causes the attack of opportunity to automatically miss. A protective spirit can defend against a number of attacks of opportunity equal to your Dexterity bonus (minimum 1) per round.</p>
<p>A protective spirit occupies your space, and moves with you. It cannot be attacked or harmed by physical attacks, but <Link to="/spell/dispel_magic">dispel magic</Link>, <Link to="/spell/disintegrate">disintegrate</Link>, a <Link to="/magic-artifact/sphere_of_annihilation">sphere of annihilation</Link>, or a <Link to="/magic-rod/rod_of_cancellation">rod of cancellation</Link> affects it. A protective spirit's AC against touch attacks is 10 + your Dexterity modifier.</p>
</>};
const _prying_eyes = {title: "Prying Eyes", jsx: <><h2 id="spell-prying_eyes-prying-eyes">Prying Eyes</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 326</Link><br/><strong>School</strong> <Link to="/spelldef/divination">divination</Link>; <strong>Level</strong> arcanist 5, mesmerist 5, occultist 5, psychic 5, sorcerer 5, spiritualist 5, witch 5, wizard 5<br/><strong>Casting Time</strong> 1 minute<br/><strong>Components</strong> V, S, M (a handful of crystal marbles)<br/><strong>Range</strong> 1 mile<br/><strong>Effect</strong> 10 or more levitating eyes<br/><strong>Duration</strong> 1 hour/level; see text<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>You create a number of semi-tangible, visible magical orbs (called "eyes") equal to 1d4 + your caster level. These eyes move out, scout around, and return as you direct them when casting the spell. Each eye can see 120 feet (normal vision only) in all directions.</p>
<p>While the individual eyes are quite fragile, they're small and difficult to spot. Each eye is a Fine construct, about the size of a small apple, that has 1 hit point, AC 18 (+8 bonus for its size), flies at a speed of 30 feet with a +20 bonus on Fly skill checks and a +16 bonus on Stealth skill checks. It has a Perception modifier equal to your caster level (maximum +15) and is subject to illusions, darkness, fog, and any other factors that affect your ability to receive visual information about your surroundings. An eye traveling in darkness must find its way by touch.</p>
<p>When you create the eyes, you specify instructions you want them to follow in a command of no more than 25 words. Any knowledge you possess is known by the eyes as well.</p>
<p>In order to report their findings, the eyes must return to your hand. Each replays in your mind all it has seen during its existence. It takes an eye 1 round to replay 1 hour of recorded images. After relaying its findings, an eye disappears.</p>
<p>If an eye ever gets more than 1 mile away from you, it instantly ceases to exist. However, your link with the eye is such that you won't know if the eye was destroyed because it wandered out of range or because of some other event.</p>
<p>The eyes exist for up to 1 hour per caster level or until they return to you. <Link to="/spell/dispel_magic">Dispel magic</Link> can destroy eyes. Roll separately for each eye caught in an area dispel. Of course, if an eye is sent into darkness, it could hit a wall or similar obstacle and destroy itself.</p>
</>};
const _prying_eyes_greater = {title: "Greater Prying Eyes", jsx: <><h2 id="spell-prying_eyes_greater-greater-prying-eyes">Greater Prying Eyes</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 326</Link><br/><strong>School</strong> <Link to="/spelldef/divination">divination</Link>; <strong>Level</strong> arcanist 8, psychic 8, sorcerer 8, witch 8, wizard 8<br/><strong>Casting Time</strong> 1 minute<br/><strong>Components</strong> V, S, M (a handful of crystal marbles)<br/><strong>Range</strong> 1 mile<br/><strong>Effect</strong> 10 or more levitating eyes<br/><strong>Duration</strong> 1 hour/level; see text<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>This spell functions like prying eyes, except that the eyes can see all things as they actually are, just as if they had true seeing with a range of 120 feet. Thus, they can navigate darkened areas at normal speed. Also, a greater prying eye's maximum Perception modifier is +25 instead of +15.</p>
</>};
const _psychic_asylum = {title: "Psychic Asylum", jsx: <><h2 id="spell-psychic_asylum-psychic-asylum">Psychic Asylum</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 181</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/phantasm">phantasm</Link>) [<Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> arcanist 6, mesmerist 5, psychic 5, sorcerer 6, wizard 6<br/><strong>Casting Time</strong> 1 swift action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> instantaneous; see text<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>You retreat into a <Link to="/rule/mindscapes">mindscape</Link> of your own making that allows you to perform a lengthy mental task in an instant. You create a mental landscape that provides succor and calm for you, such as a library, sitting room, garden, or childhood tree house. You can spend up to 15 minutes in your psychic asylum. While you are within, no time passes for your body, and when you emerge you can continue with your turn. The mindscape is overt, finite, and has a rapid passage of time.</p>
<p>While within the mindscape, you can consult any text, recall any conversation, or remember any image that you have been exposed to with perfect clarity and recollection, as if you had an eidetic memory. You must have seen or heard the material within a time frame of 1 week per level. For example, you might wish to reexamine a passage of text from an ancient manuscript you rapidly scanned in a library 2 weeks prior. While in the psychic asylum, you can perfectly recall the precise layout of the text within the ancient manuscript and read it word for word. Once you emerge from the psychic asylum, you can recall the details of what you had just studied as clearly as if you had just looked at it, but you no longer have total recall of the material.</p>
<p>If you're able to prepare spells, you can use the time to prepare a single spell. For example, if you were poisoned, you could use your swift action to cast psychic asylum, pray and meditate for the full 15 minutes to gain neutralize poison, then emerge from the mindscape and immediately cast the spell upon yourself as your standard action.</p>
<p>Any mind-affecting spell that was affecting you before you cast the spell continues to expend its duration on you while you are within the psychic asylum, so you can use this spell to wait out the effects of such a condition. Effects that are currently affecting your body do not expend additional duration while you are in the psychic asylum, but you also don't experience their effects during the time spent there.</p>
</>};
const _psychic_crush_1 = {hasJL:true,title: "Psychic Crush I", jsx: <><div className="jumpList" id="spell-psychic_crush_1-jumplist"><h2>Jump to:</h2><ul><li><InnerLink toTop to="spell-psychic_crush_1-psychic-crush-ii">Psychic Crush II</InnerLink></li><li><InnerLink toTop to="spell-psychic_crush_1-psychic-crush-iii">Psychic Crush III</InnerLink></li><li><InnerLink toTop to="spell-psychic_crush_1-psychic-crush-iv">Psychic Crush IV</InnerLink></li><li><InnerLink toTop to="spell-psychic_crush_1-psychic-crush-v">Psychic Crush V</InnerLink></li></ul></div><h2 id="spell-psychic_crush_1-psychic-crush-i">Psychic Crush I</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 182</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link> [<Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> psychic 5<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one creature<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Will partial and Fortitude partial, see text; <strong>Spell Resistance</strong> yes</p><p>Using your psychic power, you invade the mind of the target and tear it asunder, causing massive internal damage to both its mind and body. If the target succeeds at the initial Will save, it is sickened for 1 round. If the target fails its Will save, it must attempt a Fortitude save (with a +4 circumstance bonus on this save if it has more than half its total hit points remaining). If it also fails the Fortitude save, the target is reduced to -1 hit points and is dying. If the target succeeds at its Fortitude save, it instead takes 3d6 points of damage + 1 point of damage per caster level, which cannot reduce the target below -1 hit point, and the target is sickened for 1 round. This attack has no effect on creatures without an Intelligence score.</p>
<h3 id="spell-psychic_crush_1-psychic-crush-ii" data-hash-target>Psychic Crush II</h3>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 182</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link> [<Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> psychic 6<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one creature<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Will partial and Fortitude partial, see text; <strong>Spell Resistance</strong> yes</p><p>This functions as psychic crush I, but on a successful Fortitude save, the target takes 5d6 points of damage + 1 point of damage per caster level. In addition, the target receives a +4 circumstance bonus on the Fortitude save only if it is at full hit points; otherwise, it gains a +2 bonus if it has more than half its total hit points remaining. This spell can be undercast.</p>
<h3 id="spell-psychic_crush_1-psychic-crush-iii" data-hash-target>Psychic Crush III</h3>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 183</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link> [<Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> psychic 7<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one creature<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Will partial and Fortitude partial, see text; <strong>Spell Resistance</strong> yes</p><p>This functions as psychic crush I, but the target takes 7d6 points of damage + 1 point of damage per caster level on a successful Fortitude save and 1 point of damage per caster level on a successful Will save. The target receives a +2 circumstance bonus on the Fortitude save if it is at full hit points, and no bonus if it has taken any damage. This spell can be undercast.</p>
<h3 id="spell-psychic_crush_1-psychic-crush-iv" data-hash-target>Psychic Crush IV</h3>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 183</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link> [<Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> psychic 8<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one creature<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Will partial and Fortitude partial, see text; <strong>Spell Resistance</strong> yes</p><p>This functions as psychic crush I, but the target takes 9d6 points of damage + 1 point of damage per caster level on a successful Fortitude or Will save. The target does not receive any saving throw bonus because of its hit points. If it is at fewer than half its total hit points, it doesn't gain a Fortitude save to resist this spell but instead proceeds as if it had automatically failed its Fortitude save. This spell can be undercast.</p>
<h3 id="spell-psychic_crush_1-psychic-crush-v" data-hash-target>Psychic Crush V</h3>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 183</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link> [<Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> psychic 9<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one creature<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Will partial and Fortitude partial, see text; <strong>Spell Resistance</strong> yes</p><p>This functions as psychic crush IV, but on a successful Fortitude or Will save, the target takes 11d6 points of damage + 1 point of damage per caster level. If it is at fewer than half its total hit points, the target takes a -2 penalty on the Will save to resist this spell. This spell can be undercast.</p>
</>};
const _psychic_image = {title: "Psychic Image", jsx: <><h2 id="spell-psychic_image-psychic-image">Psychic Image</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 183</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/shadow_subschool">_subschool</Link>); <strong>Level</strong> psychic 9<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V<br/><strong>Range</strong> long (400 ft. + 40 ft./level)<br/><strong>Effect</strong> one shadow duplicate<br/><strong>Duration</strong> 1 round/level (D)<br/><strong>Saving Throw</strong> Will disbelief (if interacted with); <strong>Spell Resistance</strong> yes</p><p>You envelop your consciousness in a quasi-real image of yourself. Your psychic image looks, sounds, and smells like you, but is intangible. While your mind occupies the image, you control it as though it were your own body, but you cannot directly affect physical objects. Your image moves with a fly speed of 60 feet and perfect maneuverability. Your senses perceive only what the image can see and hear while occupying it, and your own body is considered blind, deaf, and helpless. You can switch between the image and your body as a swift action. While your mind is in your body, the image is similarly helpless.</p>
<p>Your image can pass through solid objects as though you are incorporeal. It cannot go farther into a solid object than your space (5 feet for a Small or Medium creature). It can't be damaged by most attacks or effects, whether or not they affect incorporeal creatures. However, mind-affecting effects targeted against or affecting your psychic image have their full effect on you whenever your mind occupies it.</p>
<p>If you desire, you can cast any psychic spell or spell-like ability with a range of touch or greater while your mind occupies your image. You can't cast non-psychic spells through the image, even if you possess them. The psychic image can cast only psychic illusion spells on itself. The spells affect other targets normally, despite originating from the psychic image.</p>
<p>Objects are affected by the psychic image as if they had succeeded at their Will saves. You need not maintain line of effect to your psychic image, but if you cross into another plane even for an instant, such as via blink, dimension door, or similar spells, the spell ends.</p>
</>};
const _psychic_leech = {title: "Psychic Leech", jsx: <><h2 id="spell-psychic_leech-psychic-leech">Psychic Leech</h2>
<p><strong>Sources</strong> <Link to="/source/occult_origins">Occult Origins pg. 29</Link><br/><strong>School</strong> <Link to="/spelldef/enchantment">enchantment</Link> (<Link to="/spelldef/compulsion">compulsion</Link>) [<Link to="/spelldef/emotion">emotion</Link>, <Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> arcanist 3, bloodrager 3, magus 3, medium 3, mesmerist 2, psychic 2, sorcerer 3, spiritualist 2, witch 2, wizard 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one living creature<br/><strong>Duration</strong> 1 minute/level (D)<br/><strong>Saving Throw</strong> Will partial; <strong>Spell Resistance</strong> yes</p><p>The target experiences feelings of ennui and lethargy, becoming fatigued for the spell's duration. While the target is fatigued and is within the spell's range, you gain a +2 enhancement bonus to Strength and Dexterity. On a successful save, the target is fatigued for only 1d4 rounds and you receive no bonus. This spell has no effect if it targets a creature that is already fatigued.</p>
</>};
const _psychic_reading = {title: "Psychic Reading", jsx: <><h2 id="spell-psychic_reading-psychic-reading">Psychic Reading</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 183</Link><br/><strong>School</strong> <Link to="/spelldef/divination">divination</Link>; <strong>Level</strong> arcanist 2, bard 2, inquisitor 2, medium 1, mesmerist 1, occultist 1, psychic 1, skald 2, sorcerer 2, spiritualist 1, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one humanoid creature<br/><strong>Duration</strong> 1 round<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> yes</p><p>You are able to read a person's surface thoughts and take cues from the person's appearance, body language, and manner of speech to infer a great deal of information about the person, even if that person is in disguise (including polymorph effects). When casting the spell, attempt a DC 20 Sense Motive check with a bonus equal to your caster level. A successful skill check reveals to you one of the following pieces of information of your choice, plus one additional piece of information for every 5 points by which your check result exceeds 20: age, alignment, class*, feats*, gender, native language, place of origin, race or ethnicity, racial traits*, religion, sexual orientation, or training in a Craft, Perform, or Profession skill. For items marked with an asterisk (*), if the target has more than one of these features, each one you discover counts as a piece of information.</p>
<p>There's a 70% chance that all information you receive is correct. This roll is made secretly. Otherwise, on a roll of 71-80, you receive one false piece of information, on a roll of 81-90 you receive two, and on a roll of 91-100 you receive three. You can't get more false information than the total number of pieces of information you discover.</p>
</>};
const _psychic_surgery = {title: "Psychic Surgery", jsx: <><h2 id="spell-psychic_surgery-psychic-surgery">Psychic Surgery</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 183</Link><br/><strong>School</strong> <Link to="/spelldef/enchantment">enchantment</Link> [<Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> mesmerist 5, psychic 6<br/><strong>Casting Time</strong> 10 minutes<br/><strong>Components</strong> V, M (diamond dust worth 250 gp)<br/><strong>Range</strong> touch<br/><strong>Target</strong> one willing and living creature<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>Psychic surgery cures the target of all Intelligence, Wisdom, and Charisma damage and restores all points permanently drained from the target's Intelligence, Wisdom, and Charisma scores. It also eliminates all ongoing insanity, confusion, and fear effects. Psychic surgery can also remove other mental afflictions, including enchantment spells and abilities, and even instantaneous effects, but in this case, if <Link to="/spell/dispel_magic">dispel magic</Link> couldn't remove the effect, psychic surgery works only if the spell level or equivalent spell level of the effect was 6th level or lower. Psychic surgery removes all effects magically altering the target's memory, even instantaneous effects, and it can restore a memory to perfect clarity like the second use of <Link to="/spell/modify_memory">modify memory</Link>.</p>
</>};
const _psychonaut_manifestation = {title: "Psychonaut Manifestation", jsx: <><h2 id="spell-psychonaut_manifestation-psychonaut-manifestation">Psychonaut Manifestation</h2>
<p><strong>Sources</strong> <Link to="/source/occult_origins">Occult Origins pg. 31</Link><br/><strong>School</strong> <Link to="/spelldef/enchantment">enchantment</Link> (<Link to="/spelldef/compulsion">compulsion</Link>) [<Link to="/spelldef/emotion">emotion</Link>, <Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> psychic 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a small piece of psychoactive cactus)<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 round/level (D)<br/><strong>Saving Throw</strong> see text; <strong>Spell Resistance</strong> no</p><p>You take a mental journey through the doors of perception to enter an altered state of consciousness. Despite this hallucinatory transmigration being entirely unreal, your mind and body fully react to it. You gain a +4 alchemical bonus to a random ability score, as well as a corresponding -2 penalty. If the bonus applies to Strength, the penalty applies to Intelligence, and vice versa. If the bonus applies to Dexterity, the penalty applies to Wisdom, and vice versa. If the bonus applies to Constitution, the penalty applies to Charisma, and vice versa. Each round as a standard action, you can explore the nooks and crannies of your imagination to further alter your corporal self. If you do so, attempt a Will save against the spell's save DC. If you succeed, randomly select another ability score and change the alchemical bonus and associated penalty accordingly. If you fail, you are dazed for 1 round instead as your mind reels from learning unexpected truths about yourself.</p>
</>};
const _pugwampis_grace = {title: "Pugwampi's Grace", jsx: <><h2 id="spell-pugwampis_grace-pugwampis-grace">Pugwampi's Grace</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_magic">Inner Sea Magic pg. 59</Link><br/><strong>School</strong> <Link to="/spelldef/enchantment">enchantment</Link> (<Link to="/spelldef/compulsion">compulsion</Link>) [<Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> arcanist 3, bard 2, skald 2, sorcerer 3, witch 3, wizard 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a pugwampi's hair)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one creature (see below)<br/><strong>Duration</strong> 1 round/level<br/><strong>Saving Throw</strong> Will negates; <strong>Spell Resistance</strong> yes</p><p>Hated by adventurers throughout the Inner Sea region, the gremlins known as pugwampis infect those around them with a malignant form of unluck - an effect that this spell emulates. If the target fails its Will save, it becomes infused with the so-called "grace of the pugwampi." A creature affected by this spell must roll two d20s whenever a situation calls for a d20 roll (such as an attack roll, a skill check, or a saving throw) and must use the lower of the two results generated. As with the aura shed by actual pugwampies, this spell has no effect on animals, gremlins, or gnolls. The effects of this spell are negated as long as a target gains any sort of luck bonus to a d20 roll (such as those granted by a luckstone or divine favor), but the spell's duration is not impacted by these effects. If the luck bonus goes away before the pugwampi's grace effect ends, the unluck returns and remains until the spell's normal duration runs out.</p>
</>};
const _punishing_armor = {title: "Punishing Armor", jsx: <><h2 id="spell-punishing_armor-punishing-armor">Punishing Armor</h2>
<p><strong>Sources</strong> <Link to="/source/agents_of_evil">Agents of Evil pg. 19</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link>; <strong>Level</strong> alchemist 1, arcanist 1, bloodrager 1, investigator 1, magus 1, shaman 1, sorcerer 1, spiritualist 1, summoner 1, wizard 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 10 minutes/level (D)<br/><strong>Saving Throw</strong> Fortitude negates, see below; <strong>Spell Resistance</strong> no</p><p>You coat yourself with a thin layer of shimmering energy. Any creature dealing nonlethal damage to you immediately takes half the amount of nonlethal damage dealt. A successful Fortitude save made by the attacking creature negates this damage.</p>
</>};
const _pup_shape = {title: "Pup Shape", jsx: <><h2 id="spell-pup_shape-pup-shape">Pup Shape</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 240</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link> (<Link to="/spelldef/polymorph">polymorph</Link>); <strong>Level</strong> arcanist 3, druid 3, hunter 3, red mantis assassin 3, sorcerer 3, witch 3, wizard 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a rag doll)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one animal<br/><strong>Duration</strong> 1 round/level<br/><strong>Saving Throw</strong> Fortitude negates (and Will special, see text); <strong>Spell Resistance</strong> yes</p><p>You transform the subject animal into a Small magical beast (or a magical beast one size category smaller than the original creature, whichever is smaller), creating a young magical version of itself for a short period of time. While in this form, the target has only 1 HD (maximum hit points), and the target takes a -4 penalty to Strength, Constitution, Intelligence and Wisdom (minimum 1). The creature also gains a +4 size bonus to Dexterity and a +2 natural bonus.</p>
<p>Any nonevil creature that attempts to attack a creature in this form must succeed at a Will saving throw (using the DC of the spell) to overcome feelings of guilt and protectiveness toward the young and innocent-seeming creature. On a failed saving throw, it cannot follow through with the attack, that part of the action is lost, and it can't directly attack the transformed creature for the duration of the spell or until the spell's target attacks it. This part of the spell is a mind-affecting emotion effect. Evil creatures have no qualms about attacking the target of this spell, in fact, some particularly heinous creatures might go out of their ways to do the target harm.</p>
</>};
const _purge_spirit = {title: "Purge Spirit", jsx: <><h2 id="spell-purge_spirit-purge-spirit">Purge Spirit</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 184</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link>; <strong>Level</strong> arcanist 4, medium 2, occultist 2, psychic 3, sorcerer 4, spiritualist 2, witch 4, wizard 4<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Target</strong> one creature or haunt<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Will partial; <strong>Spell Resistance</strong> yes</p><p>Purge spirit rips away at the target's spiritual substance, scattering it over a wide area and hampering the target's ability to reform. The target takes 1d6 points of damage per caster level (maximum 10d6) and is staggered for 1 round. On a successful saving throw, the target takes half damage and is not staggered. This spell affects astrally projected creatures, ethereal creatures, haunts, incorporeal creatures, mediums channeling a spirit, and phantoms, and at the GM's discretion can affect other spirits or creatures made of ectoplasm. Incorporeal creatures take full damage from purge spirit.</p>
</>};
const _purging_finale = {title: "Purging Finale", jsx: <><h2 id="spell-purging_finale-purging-finale">Purging Finale</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 237</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/healing">healing</Link>); <strong>Level</strong> bard 3, skald 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one living creature<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>You must have a bardic performance in effect to cast this spell. With a flourish, you immediately end your bardic performance, removing one of the following conditions on a creature within range affected by your bardic performance: cowering, dazzled, exhausted, paralyzed, shaken, or stunned.</p>
</>};
const _purified_calling = {title: "Purified Calling", jsx: <><h2 id="spell-purified_calling-purified-calling">Purified Calling</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 237</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/healing">healing</Link>); <strong>Level</strong> summoner 4, unchained summoner 4<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a stick of incense)<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 minute</p><p>Your eidolon is restored to full health when you summon it. Upon casting this spell, you must immediately begin the ritual to summon your eidolon. Upon completion of the ritual, your eidolon appears at full hit points and without any damage or penalties to its ability scores, regardless of its previous condition. In addition, any temporary negative conditions affecting your eidolon are immediately removed. Permanent conditions and ability drain are not affected by this spell.</p>
</>};
const _purify_body = {title: "Purify Body", jsx: <><h2 id="spell-purify_body-purify-body">Purify Body</h2>
<p><strong>Sources</strong> <Link to="/source/healers_handbook">Healer's Handbook pg. 9</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/healing">healing</Link>); <strong>Level</strong> alchemist 4, cleric 4, medium 4, oracle 4, paladin 4, psychic 5, warpriest 4<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> touch<br/><strong>Target</strong> living creature touched<br/><strong>Duration</strong> instantaneous and 1 hour or until discharged<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>You align the target's chakras and soothe any unwanted imperfections found within its physical form, leaving its body pristine and without any pain or weakness.</p>
<p>You restore a number of hit points to the creature equal to 3d8 + 1 per caster level (maximum +20). If the healing would cause the target to exceed its maximum hit points, the target immediately gains half the excess healing from this spell as temporary hit points that last for 1 hour. These temporary hit points are lost first when the target takes damage (although some temporary hit points are lost even before these temporary hit points, such as the temporary hit points from the shell of succor oracle mystery or the shell of succor hex granted by the restoration spirit specialization).</p>
<p>This spell also ends any pain effects, removes all physical ability score damage (from Strength, Dexterity, and Constitution), and removes the following conditions: blinded, dazzled, deafened, nauseated, paralyzed, and sickened.</p>
</>};
const _purify_food_and_drink = {title: "Purify Food and Drink", jsx: <><h2 id="spell-purify_food_and_drink-purify-food-and-drink">Purify Food and Drink</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 328</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> adept 0, cleric 0, druid 0, hunter 0, occultist 0, oracle 0, shaman 0, warpriest 0<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> 10 ft.<br/><strong>Target</strong> 1 cu. ft./level of contaminated food and water<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Will negates (object); <strong>Spell Resistance</strong> yes (object)</p><p>This spell makes spoiled, rotten, diseased, poisonous, or otherwise contaminated food and water pure and suitable for eating and drinking. This spell does not prevent subsequent natural decay or spoilage. Unholy water and similar food and drink of significance is spoiled by purify food and drink, but the spell has no effect on creatures of any type nor upon magic potions. Water weighs about 8 pounds per gallon. One cubic foot of water contains roughly 8 gallons and weighs about 60 pounds.</p>
</>};
const _putrefy_food_and_drink = {title: "Putrefy Food and Drink", jsx: <><h2 id="spell-putrefy_food_and_drink-putrefy-food-and-drink">Putrefy Food and Drink</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 237</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link> [<Link to="/spelldef/poison">poison</Link>]; <strong>Level</strong> witch 0<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> 10 ft.<br/><strong>Target</strong> 1 cu. ft./level of food and water or one potion; see text<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Will negates (object); <strong>Spell Resistance</strong> yes (object)</p><p>This spell causes otherwise edible food to rot and spoil instantly, and water and other liquids to become brackish and undrinkable. Holy water and similar food and drink of significance are spoiled by putrefy food and drink, but the spell has no effect on creatures of any type, nor upon unholy water. Water weighs about 8 pounds per gallon. One cubic foot of water contains roughly 8 gallons and weighs about 60 pounds.</p>
<p>Although potions and elixirs are unaffected by the normal use of the spell, you can instead choose to target a single such object with this spell, destroying it if it fails a saving throw.</p>
</>};
const _puzzle_box = {title: "Puzzle Box", jsx: <><h2 id="spell-puzzle_box-puzzle-box">Puzzle Box</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_monster_codex">Inner Sea Monster Codex pg. 41</Link><br/><strong>School</strong> <Link to="/spelldef/enchantment">enchantment</Link> (<Link to="/spelldef/compulsion">compulsion</Link>) [<Link to="/spelldef/curse">curse</Link>, <Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> arcanist 3, bard 2, skald 2, sorcerer 3, witch 3, wizard 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one creature or one object up to 5 lbs./level<br/><strong>Duration</strong> 1 round/level or permanent; see text<br/><strong>Saving Throw</strong> Will negates or none; <strong>Spell Resistance</strong> yes</p><p>This spell causes even commonly used objects to become conundrums. When cast on a creature, the target loses all weapon and shield proficiencies. The target also forgets how to use all <Link to="/misc/spell_completion">spell-completion</Link>, <Link to="/misc/spell_trigger">spell-trigger</Link>, and use-activated magic items, as well as any mundane items used as part of a skill check, imposing a -5 penalty on all ability and skill checks attempted with such items. These effects last for 1 round per level. As a move action, the target can attempt a skill check to negate the effects of this spell for one object. Weapons, shields, and mundane objects require a successful Craft skill check of the type required to craft the item in question, with a DC equal to the spell's save DC. Magic items require a successful Spellcraft or Use Magic Device skill check against the spell's save DC.</p>
<p>Alternatively, this spell can be cast on a single touched object that weighs up to 5 pounds per the caster's level. Use of this object becomes a puzzle even to those previously familiar with it. Any creature attempting to use an item affected in this way is treated as though the creature was the target of puzzle box for that item only. When cast on an object, the duration of this spell is permanent.</p>
</>};
const _pyrotechnic_eruption = {title: "Pyrotechnic Eruption", jsx: <><h2 id="spell-pyrotechnic_eruption-pyrotechnic-eruption">Pyrotechnic Eruption</h2>
<p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 125</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link> [<Link to="/spelldef/fire">fire</Link>]; <strong>Level</strong> arcanist 4, bloodrager 3, magus 4, occultist 4, sorcerer 4, wizard 4<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a pinch of coal)<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Target</strong> one creature<br/><strong>Duration</strong> see text<br/><strong>Saving Throw</strong> Reflex half (see text); <strong>Spell Resistance</strong> yes</p><p>The caster causes jets of flame to erupt from the ground and surround the target. The target takes 1d6 points of damage per caster level (maximum 15d6) unless it succeeds at a Reflex save for half damage. The blaze surrounds the target for the duration of the spell, forcing the creature to attempt a new save each round. Each round, the damage dealt is reduced to half as many d6; the spell expires when it would deal no damage. If the target moves, the pyrotechnic eruption follows, even if the target teleports.</p>
<p>Anyone attempting to touch the target takes damage, using the same amount of dice as the last time the target attempted a save (Reflex half). A creature can take the place of the target by bull rushing or grappling it and switching places. The new creature then automatically takes the current round's damage with no saving throw and can begin to attempt Reflex saves starting on its next turn.</p>
</>};
const _pyrotechnics = {title: "Pyrotechnics", jsx: <><h2 id="spell-pyrotechnics-pyrotechnics">Pyrotechnics</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 328</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> arcanist 2, bloodrager 2, bard 2, magus 2, mesmerist 2, psychic 2, red mantis assassin 2, skald 2, sorcerer 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (one fire source)<br/><strong>Range</strong> long (400 ft. + 40 ft./level)<br/><strong>Target</strong> one fire source, up to a 20-ft. cube<br/><strong>Duration</strong> 1d4+1 rounds, or 1d4+1 rounds after creatures leave the smoke cloud; see text<br/><strong>Saving Throw</strong> Will negates or Fortitude negates; see text; <strong>Spell Resistance</strong> yes or no; see text</p><p>Pyrotechnics turns a fire into a burst of blinding fireworks or a thick cloud of choking smoke, depending on your choice. The spell uses one fire source, which is immediately extinguished. A fire so large that it exceeds a 20-foot cube is only partly extinguished. Magical fires are not extinguished, although a fire-based creature used as a source takes 1 point of damage per caster level.</p>
<p><em>Fireworks:</em> The fireworks are a flashing, fiery, momentary burst of glowing, colored aerial lights. This effect causes creatures within 120 feet of the fire source to become blinded for 1d4+1 rounds (Will negates). These creatures must have line of sight to the fire to be affected. Spell resistance can prevent blindness.</p>
<p><em>Smoke Cloud:</em> A stream of smoke billows out from the fire, forming a choking cloud that spreads 20 feet in all directions and lasts for 1 round per caster level. All sight, even darkvision, is ineffective in or through the cloud. All within the cloud take -4 penalties to Strength and Dexterity (Fortitude negates). These effects last for 1d4+1 rounds after the cloud dissipates or after the creature leaves the area of the cloud. Spell resistance does not apply.</p>
</>};
const _screen = {title: "Screen", jsx: <><h2 id="spell-screen-screen">Screen</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 337</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/glamer">glamer</Link>); <strong>Level</strong> arcanist 8, psychic 8, sorcerer 8, wizard 8<br/><strong>Casting Time</strong> 10 minutes<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Area</strong> 30-ft. cube/level (S)<br/><strong>Duration</strong> 24 hours<br/><strong>Saving Throw</strong> none or Will disbelief (if interacted with); see text; <strong>Spell Resistance</strong> no</p><p>This spell creates a powerful protection from scrying and observation. When casting the spell, you dictate what will and will not be observed in the spell's area. The illusion created must be stated in general terms. Once the conditions are set, they cannot be changed. Attempts to scry the area automatically detect the image stated by you with no save allowed. Sight and sound are appropriate to the illusion created. Direct observation may allow a save (as per a normal illusion), if there is cause to disbelieve what is seen. Even entering the area does not cancel the illusion or necessarily allow a save, assuming that hidden beings take care to stay out of the way of those affected by the illusion.</p>
</>};
const _scribes_binding = {title: "Scribe's Binding", jsx: <><h2 id="spell-scribes_binding-scribes-binding">Scribe's Binding</h2>
<p><strong>Sources</strong> <Link to="/source/spymasters_handbook">Spymaster's Handbook pg. 29</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link> (<Link to="/spelldef/polymorph">polymorph</Link>); <strong>Level</strong> arcanist 9, occultist 6, sorcerer 9, witch 9, wizard 9<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, F (a book bound in precious metals and treated with rare oils, worth 1,000 gp per HD of the target)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> permanent<br/><strong>Saving Throw</strong> Fortitude negates; <strong>Spell Resistance</strong> yes</p><p>Hermea's benevolent Council of Enlightenment uses this spell to humanely preserve their society's greatest minds from the ravages of time, though it has seen far more sinister employment when put to use by other organizations that have since discovered its utility. This spell binds a single creature into a prepared book, sustaining it in suspended animation and filling the book with its experience and knowledge. The tome weighs 10 pounds and has one page for every day of the subject's life. The cover and binding transform to reflect the subject's appearance, interests, and tastes. Every thought and memory - including those the target may have forgotten long ago - are perfectly transcribed within the enchanted pages, penned in excruciating detail in the language that the creature was thinking or speaking in when the event occurred. If a memory includes dialogue in a language the subject didn't understand, that dialogue is reproduced phonetically, and must be translated by a reader who knows that language. Any alterations to a subject's memories - such as by a <Link to="/spell/modify_memory">modify memory</Link> spell - appear in a subtly different script; a successful DC 35 Linguistics check is needed to identify this.</p>
<p>Spells that modify or remove text - such as <Link to="/spell/erase">erase</Link> or <Link to="/spell/secret_page">secret page</Link> - also affect the target's memory if they persist after its release. <em>Modify memory</em> can be used to repair any changes to its original state, or alter the accounts recorded within the book. A creature imprisoned by scribe's binding automatically fails any saving throws against effects to change or modify its memories.</p>
<p>A target bound by this spell can be freed by only <Link to="/spell/freedom">freedom</Link>, <Link to="/spell/miracle">miracle</Link>, or <Link to="/spell/wish">wish</Link>. <Link to="/spell/polymorph_any_object">Polymorph any object</Link> restores the target's normal form for 24 hours. Scribe's binding makes the imprisoning tome supernaturally durable (hardness 20, 10 hp per HD the imprisoned creature had). Destroying the tome immediately slays the creature imprisoned within.</p>
</>};
const _scriveners_chant = {title: "Scrivener's Chant", jsx: <><h2 id="spell-scriveners_chant-scriveners-chant">Scrivener's Chant</h2>
<p><strong>Sources</strong> <Link to="/source/seekers_of_secrets">Seekers of Secrets pg. 17</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> arcanist 0, bard 0, cleric 0, oracle 0, skald 0, sorcerer 0, warpriest 0, wizard 0<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (fine sand and a vial of ink)<br/><strong>Range</strong> 5 ft.<br/><strong>Target</strong> one or more written objects<br/><strong>Duration</strong> concentration, up to 1 minute/level<br/><strong>Saving Throw</strong> Will (harmless, object); <strong>Spell Resistance</strong> yes (object)</p><p>This spell imbues a quill with animate energy and rapidly transcribes words from one page to another. The quill copies a written work at the rate of one normal-sized page per minute. The Linguistics skill can be used to make a convincing copy, but otherwise the reproduction is written in the hand of the caster. You must concentrate upon the material being duplicated for the spell's duration and provide new blank pages as required. The scrivener's chant requires blank paper and a quill or other writing materials, in addition to the material components.</p>
<p>This spell cannot duplicate magical writing (including spells and magical scrolls), though it can duplicate non-magical writing from a magical source.</p>
</>};
const _scrying = {title: "Scrying", jsx: <><h2 id="spell-scrying-scrying">Scrying</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 337</Link><br/><strong>School</strong> <Link to="/spelldef/divination">divination</Link> (<Link to="/spelldef/scrying">scrying</Link>); <strong>Level</strong> arcanist 4, bard 3, cleric 5, druid 4, hunter 4, medium 3, mesmerist 3, occultist 4, oracle 5, psychic 4, shaman 4, skald 3, sorcerer 4, spiritualist 5, warpriest 5, witch 4, wizard 4<br/><strong>Casting Time</strong> 1 hour<br/><strong>Components</strong> V, S, F (a silver mirror worth 1,000 gp), M/DF (a pool of water)<br/><strong>Range</strong> see text<br/><strong>Effect</strong> magical sensor<br/><strong>Duration</strong> 1 minute/level<br/><strong>Saving Throw</strong> Will negates; <strong>Spell Resistance</strong> yes</p><p>You can observe a creature at any distance. If the subject succeeds on a Will save, the spell fails. The difficulty of the save depends on how well your knowledge of the subject and what sort of physical connection (if any) you have to that creature. Furthermore, if the subject is on another plane, it gets a +5 bonus on its Will save.</p>
<ScrollContainer id="spell-scrying--table-0"><table>
<thead>
<tr>
<th>Knowledge</th>
<th>Will Save Modifier</th>
</tr>
</thead>
<tbody><tr>
<td>None*</td>
<td>+10</td>
</tr>
<tr>
<td>Secondhand (you have heard of the subject)</td>
<td>+5</td>
</tr>
<tr>
<td>Firsthand (you have met the subject)</td>
<td>+0</td>
</tr>
<tr>
<td>Familiar (you know the subject well)</td>
<td>-5</td>
</tr>
</tbody></table></ScrollContainer>
<p>*You must have some sort of connection (see below) to a creature of which you have no knowledge.</p>
<ScrollContainer id="spell-scrying--table-1"><table>
<thead>
<tr>
<th>Connection</th>
<th>Will Save Modifier</th>
</tr>
</thead>
<tbody><tr>
<td>Likeness or picture</td>
<td>-2</td>
</tr>
<tr>
<td>Possession or garment</td>
<td>-4</td>
</tr>
<tr>
<td>Body part, lock of hair, bit of nail, etc.</td>
<td>-10</td>
</tr>
</tbody></table></ScrollContainer>
<p>If the save fails, you can see and hear the subject and its surroundings (approximately 10 feet in all directions of the subject). If the subject moves, the sensor follows at a speed of up to 150 feet.</p>
<p>As with all divination (scrying) spells, the sensor has your full visual acuity, including any magical effects. In addition, the following spells have a 5% chance per caster level of operating through the sensor: <Link to="/spell/detect_chaos">detect chaos</Link>, <Link to="/spell/detect_evil">detect evil</Link>, <Link to="/spell/detect_good">detect good</Link>, <Link to="/spell/detect_law">detect law</Link>, <Link to="/spell/detect_magic">detect magic</Link>, and <Link to="/spell/message">message</Link>.</p>
<p>If the save succeeds, you can't attempt to scry on that subject again for at least 24 hours.</p>
<h3 id="spell-scrying-greater-scrying">Greater Scrying</h3>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 337</Link><br/><strong>School</strong> <Link to="/spelldef/divination">divination</Link> (<Link to="/spelldef/scrying">scrying</Link>); <strong>Level</strong> arcanist 7, bard 6, cleric 7, druid 7, mesmerist 6, occultist 6, oracle 7, psychic 7, shaman 7, skald 6, sorcerer 7, witch 7, wizard 7<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> see text<br/><strong>Effect</strong> magical sensor<br/><strong>Duration</strong> 1 hour/level<br/><strong>Saving Throw</strong> Will negates; <strong>Spell Resistance</strong> yes</p><p>This spell functions like scrying, except as noted above. Additionally, all of the following spells function reliably through the sensor: <Link to="/spell/detect_chaos">detect chaos</Link>, <Link to="/spell/detect_evil">detect evil</Link>, <Link to="/spell/detect_good">detect good</Link>, <Link to="/spell/detect_law">detect law</Link>, <Link to="/spell/detect_magic">detect magic</Link>, <Link to="/spell/message">message</Link>, <Link to="/spell/read_magic">read magic</Link>, and <Link to="/spell/tongues">tongues</Link>.</p>
</>};
const _sculpt_corpse = {title: "Sculpt Corpse", jsx: <><h2 id="spell-sculpt_corpse-sculpt-corpse">Sculpt Corpse</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 241</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link>; <strong>Level</strong> arcanist 1, occultist 1, sorcerer 1, wizard 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (lump of wax)<br/><strong>Range</strong> touch<br/><strong>Target</strong> one dead creature touched<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Will partial, see text; <strong>Spell Resistance</strong> no</p><p>With a clammy caress and a word to the powers lurking beyond death, you can reshape a dead body look like another creature or even a specific person so long as you have first-hand knowledge of how that creature or person actually looks. You can make the corpse one size larger or smaller and change anything else about it including its apparent type, gender, or age. Creatures with a reason to suspect deception may make a Will saving throw to realize that the corpse was altered. If you chose to make the corpse look like a specific individual anyone who knows that individual can make a Will save to realize that the corpse is not actually that person. However, if a creature fails its Will save by 5 or less they believe the corpse is that of someone who closely resembled the person they knew rather than a deliberate fake. This spell merely changes the appearance of the corpse. Any spell or effect that targets the corpse (such as <Link to="/spell/speak_with_dead">speak with dead</Link> or <Link to="/spell/raise_dead">raise dead</Link>) treats it as if it still had its original appearance.</p>
</>};
const _sculpt_simulacrum = {title: "Sculpt Simulacrum", jsx: <><h2 id="spell-sculpt_simulacrum-sculpt-simulacrum">Sculpt Simulacrum</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 236</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> arcanist 2, psychic 2, red mantis assassin 2, sorcerer 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> touch<br/><strong>Target</strong> simulacrum touched<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Fortitude negates; <strong>Spell Resistance</strong> yes</p><p>You create cosmetic changes to a simulacrum, similar to disguise self, except the changes are physical rather than illusory. This does not change any of the simulacrum's abilities.</p>
</>};
const _sculpt_sound = {title: "Sculpt Sound", jsx: <><h2 id="spell-sculpt_sound-sculpt-sound">Sculpt Sound</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 338</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> bard 3, skald 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Targets</strong> one creature or object/level, no two of which can be more than 30 ft. apart<br/><strong>Duration</strong> 1 hour/level (D)<br/><strong>Saving Throw</strong> Will negates (object); <strong>Spell Resistance</strong> yes (object)</p><p>You can change the sounds that creatures or objects make. You can create sounds where none exist, deaden sounds, or transform sounds into other sounds. All affected creatures or objects must be transmuted in the same way. Once the transmutation is made, you cannot change it. You can change the qualities of sounds but cannot create words with which you are unfamiliar yourself.</p>
<p>A spellcaster whose voice is changed dramatically is unable to cast spells with verbal components.</p>
</>};
const _sculpted_cape = {title: "Sculpted Cape", jsx: <><h2 id="spell-sculpted_cape-sculpted-cape">Sculpted Cape</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_armory_2">Adventurer's Armory 2 pg. 21</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> arcanist 1, bard 1, hunter 1, occultist 1, ranger 1, shaman 1, skald 1, sorcerer 1, witch 1, wizard 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, F (cape or loose outer garment)<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 minute/level</p><p>Your cape, cloak, or shawl stiffens and maintains its shape even if removed. A sculpted cape has hardness 2 and a number of hit points equal to your caster level, and it can support 1 pound of weight per caster level. An unworn sculpted cape can provide cover.</p>
</>};
const _sea_of_dust = {title: "Sea of Dust", jsx: <><h2 id="spell-sea_of_dust-sea-of-dust">Sea of Dust</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 234</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link> [<Link to="/spelldef/water">water</Link>]; <strong>Level</strong> druid 9<br/><strong>Casting Time</strong> 1 hour<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> 0 ft.<br/><strong>Area</strong> 2-mile-radius emanation<br/><strong>Duration</strong> permanent<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>You cause all areas of water to which you have line of effect to recede as if you had cast control water. Exposed water that enters the area ebbs away, evaporating or leaching into the ground at a rate of 1 foot of depth per hour. Living creatures in the area when the spell is cast are parched with thirst and take a -4 penalty on Constitution checks to resist the effects of a hot climate, and their daily water requirement to avoid thirst doubles. Plant creatures and inanimate plants take 1d6 points of nonlethal damage per hour after the first 24 hours, which bypasses hardness and damage reduction. Living creatures with the aquatic or water subtype, unless completely immersed in water, must attempt a DC 20 Constitution check each hour no matter how much water they drink. A creature that fails takes 1d6 points of nonlethal damage and becomes fatigued until it recovers from the nonlethal damage.</p>
<p>After 1 week, the soil in the area of sea of dust begins to break down and blow away. Moderate winds have a 50% chance each hour to cause sandstorms. This chance increases to 75% in strong winds and 100% in severe or stronger winds. Short-duration wind effects such as <Link to="/spell/gust_of_wind">gust of wind</Link> create sandstorms with the same area and duration as the spell, plus an identical duration after the spell ends.</p>
<p>After 1 month, the soil in an area affected by sea of dust has virtually disintegrated. The area is treated as a shallow bog for the purposes of movement, with a 25% chance each hour to encounter an area equivalent to a deep bog 2d6&times;10 feet across, and a 5% chance to encounter a collapsing dust drift equivalent to quicksand 1d6&times;5 feet across. The affected region remains desert-like in condition until the magic is dispelled, at which point the region recovers and returns to its original terrain over the course of time (this may take only days or weeks, or it could take months or even years, subject to GM discretion). This spell has no effect if cast on an entirely aquatic region. If the spell is cast on an island, the effects of the spell extend to the shore but not beyond.</p>
</>};
const _sea_steed = {title: "Sea Steed", jsx: <><h2 id="spell-sea_steed-sea-steed">Sea Steed</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 234</Link>, <Link to="/source/animal_archive">Animal Archive pg. 25</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link> (<Link to="/spelldef/polymorph">polymorph</Link>); <strong>Level</strong> druid 2, hunter 2, paladin 2, ranger 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> touch<br/><strong>Target</strong> a creature you are mounted upon<br/><strong>Duration</strong> 10 minutes/level (D)<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>The target adapts to life in the water, gaining piscine scales that cover its body and growing fins in place of feet. It gains the aquatic subtype, the amphibious quality, and a swim speed equal to its base speed before it came under the effect of this spell. While under the effects of this spell, the target's base speed is reduced by 10 feet (minimum 10 feet).</p>
<h3 id="spell-sea_steed-sea-stallion">Sea Stallion</h3>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 234</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link> (<Link to="/spelldef/polymorph">polymorph</Link>); <strong>Level</strong> druid 4, hunter 4, paladin 4, ranger 4<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> touch<br/><strong>Target</strong> a creature you are mounted upon<br/><strong>Duration</strong> 10 minutes/level (D)<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>This spell functions as sea steed, but as long as you stay mounted on the target, you also gain the amphibious quality and your melee attacks function as if you were under the effect of freedom of movement. The benefits you gain from this spell are not polymorph effects. If you dismount from the target, you retain the amphibious quality for up to 1 minute, but not the other benefits. You regain all of the benefits once you mount the target creature again.</p>
</>};
const _sealed_life = {title: "Sealed Life", jsx: <><h2 id="spell-sealed_life-sealed-life">Sealed Life</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 185</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link>; <strong>Level</strong> medium 2, spiritualist 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one creature<br/><strong>Duration</strong> 1 round/level<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> yes</p><p>You seal the life force within the target, preventing it from sharing its vitality with others. Affected creatures can't transfer damage to or from another, such as through <Link to="/spell/shield_other">shield other</Link>, a spiritualist's life bond, or a summoner's life link. Effects such as vampiric touch that steal vitality from others deal damage normally, but provide no benefits.</p>
</>};
const _sealed_life_greater = {title: "Greater Sealed Life", jsx: <><h2 id="spell-sealed_life_greater-greater-sealed-life">Greater Sealed Life</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 185</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link>; <strong>Level</strong> spiritualist 6<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one creature<br/><strong>Duration</strong> 1 minute/level<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> yes</p><p>This spell functions as <Link to="/spell/sealed_life">sealed life</Link>, except it additionally provides the benefits of death ward and renders its targets immune to effects that extract or transfer its soul, such as possession and trap the soul. This spell prevents a soul from returning to its body if it has already departed, until the spell's duration expires.</p>
</>};
const _sealed_sending = {title: "Sealed Sending", jsx: <><h2 id="spell-sealed_sending-sealed-sending">Sealed Sending</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_intrigue">Inner Sea Intrigue pg. 61</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/creation">creation</Link>) [<Link to="/spelldef/language_dependent">language-dependent</Link>]; <strong>Level</strong> arcanist 5, sorcerer 5, wizard 5<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> unlimited<br/><strong>Effect</strong> one nonmagical parchment with a written message<br/><strong>Duration</strong> 1 hour/level or until discharged<br/><strong>Saving Throw</strong>  (harmless); <strong>Spell Resistance</strong> no (harmless)</p><p>You create a scroll bearing a message in any language you can speak, with a maximum length of 50 words. The scroll magically appears anywhere you have viewed at least once on the same plane of existence you are on now. When the spell ends or when the message has been read completely, the scroll disintegrates, leaving no trace. This spell cannot be detected, traced, or blocked by any spell of a lower level.</p>
</>};
const _seamantle = {title: "Seamantle", jsx: <><h2 id="spell-seamantle-seamantle">Seamantle</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 241</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/creation">creation</Link>) [<Link to="/spelldef/water">water</Link>]; <strong>Level</strong> arcanist 8, druid 8, sorcerer 8, wizard 8<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a cup of water)<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 minute/level</p><p>You sheathe yourself within a churning column of pure elemental water up to 30 feet high that fills your space. You gain a swim speed equal to your land speed and can see, hear, and breathe normally within the seamantle, but attacks against you are treated as if you were under the surface of the water. You gain improved cover (+8 cover bonus to AC, +4 bonus on Reflex saves) against foes that do not have freedom of movement effects. The cover granted by the seamantle does not enable you to make Stealth checks or prevent attacks of opportunity. Magical attacks against you are unaffected unless they require attack rolls or state that they do not function underwater (such as cloudkill).</p>
<p>The seamantle blocks line of effect for any fire spell or supernatural fire effect, but enemies can attempt to use fire spells within the seamantle; this requires a caster level check (DC 20 + spell level), and if successful the fire spell takes effect as a bubble of steam contained within the seamantle rather than its usual effect.</p>
<p>The seamantle allows you to make a slam attack by forming a pseudopod of water, inflicting damage appropriate for your size. This slam attack has a reach of 30 feet. In addition, as a standard action, you can attempt to extinguish fires by touch. You automatically extinguish up to a 10-foot cube of normal fire. Against magical fire effects, your touch acts as <Link to="/spell/dispel_magic">dispel magic</Link>; this also applies to any non-instantaneous fire affect that comes into contact with you (such as <Link to="/spell/flame_blade">flame blade</Link>, <Link to="/spell/flaming_sphere">flaming sphere</Link>, or <Link to="/spell/incendiary_cloud">incendiary cloud</Link>). Even if you fail to extinguish a fire, you are not harmed by it. A <Link to="/magic-enh/flaming">flaming</Link> or <Link to="/magic-enh/flaming_burst">flaming burst</Link> weapon that strikes you has its power suppressed for 1d4 rounds if the wielder fails a Fortitude save.</p>
</>};
const _searching_shadows = {title: "Searching Shadows", jsx: <><h2 id="spell-searching_shadows-searching-shadows">Searching Shadows</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_intrigue">Inner Sea Intrigue pg. 62</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/shadow_subschool">_subschool</Link>) [<Link to="/spelldef/shadow_descriptor">_descriptor</Link>]; <strong>Level</strong> arcanist 2, bard 2, skald 2, sorcerer 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Effect</strong> shadows in a 10-foot-radius spread<br/><strong>Duration</strong> concentration<br/><strong>Saving Throw</strong> Reflex partial; <strong>Spell Resistance</strong> yes</p><p>Strands of shadow probe an area, searching for a creature or object you specify by shape, size, or texture. Each round, the shadows attempt a Perception check on the squares they touch with a total bonus equal to your caster level + your Charisma or Intelligence modifier, whichever is higher. You can move the shadows up to 30 feet or change the search criteria as part of concentrating on the spell. Whenever the shadows come into contact with a creature with spell resistance, you must attempt a caster level check to overcome its spell resistance. If you fail, the spell ends.</p>
<p>When the shadows locate a desired item or creature, you are aware of its shape and size and can order the shadows to try to seize it. If the shadows are seeking a creature, the area they cover becomes difficult terrain for that creature, and the creature must succeed at a Reflex saving throw or become entangled and unable to move. Changing the criteria of the creature or object sought or moving the shadows away from an entangled target frees it. If the target is an object carried by a creature, the shadows attempt a disarm or steal combat maneuver check as appropriate, using the same modifier as for their Perception check. The shadows can pick up and move unattended, nonmagical objects that weigh up to 5 pounds.</p>
</>};
const _searing_light = {title: "Searing Light", jsx: <><h2 id="spell-searing_light-searing-light">Searing Light</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 338</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link>; <strong>Level</strong> cleric 3, inquisitor 3, oracle 3, warpriest 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Effect</strong> ray<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> yes</p><p>Focusing divine power like a ray of the sun, you project a blast of light from your open palm. You must succeed on a ranged touch attack to strike your target. A creature struck by this ray of light takes 1d8 points of damage per two caster levels (maximum 5d8). An undead creature takes 1d6 points of damage per caster level (maximum 10d6), and an undead creature particularly vulnerable to bright light takes 1d8 points of damage per caster level (maximum 10d8). A construct or inanimate object takes only 1d6 points of damage per two caster levels (maximum 5d6).</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="spell-searing_light--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Searing Light</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 107</Link><br/>The spell's damage increases to 1d6 per caster level (maximum 10d6). The damage dealt to an undead creature increases to 1d8 points of damage per caster level (maximum 10d8), or 2d6 per caster level (maximum 20d6) if the undead is vulnerable to bright light. The damage dealt to constructs increases to 1d8 points of damage per 2 caster levels (maximum 5d8). If a creature struck has light sensitivity or light blindness, it takes the penalty from that weakness for 1 round after being struck by the light.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _sebaceous_twin = {title: "Sebaceous Twin", jsx: <><h2 id="spell-sebaceous_twin-sebaceous-twin">Sebaceous Twin</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_119_prisoners_of_the_blight">Pathfinder #119: Prisoners of the Blight pg. 70</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> arcanist 3, cleric 3, druid 3, hunter 3, oracle 3, sorcerer 3, warpriest 3, witch 3, wizard 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> touch<br/><strong>Target</strong> living creature touched<br/><strong>Duration</strong> 1 round/level (see text)<br/><strong>Saving Throw</strong> none (see text); <strong>Spell Resistance</strong> yes</p><blockquote>
<p><em>Worshippers of <Link to="/faith/cyth_vsug">Cyth-V'sug</Link> have access to the following spell.</em></p>
</blockquote>
<p>By touching a living target, you cause a half-formed, parasitic clone of the target to burst from its midsection. The twin dangles from the target's body, making it difficult for the target to move easily and imparting a -2 penalty on Acrobatics and Climb checks. In addition, for the spell's duration, the target must succeed at a Fortitude saving throw at the start of its turn each round, or else it takes 1 point of Constitution damage and is sickened for that round as the twin siphons off its blood. Each time the target receives any healing (magical or otherwise), the duration of this spell is extended by 1 round. Each attack that deals damage to the target reduces the duration of this spell by 1 round. If the duration reaches 0 rounds in this manner, the twin is violently excised from the body, and the target takes 1d6 points of bleed damage (which can be healed as normal).</p>
<p>The effect of sebaceous twin counts as a disease effect with a DC equal to the spell's saving throw DC.</p>
</>};
const _secluded_grimoire = {title: "Secluded Grimoire", jsx: <><h2 id="spell-secluded_grimoire-secluded-grimoire">Secluded Grimoire</h2>
<p><strong>Sources</strong> <Link to="/source/magic_tactics_toolbox">Magic Tactics Toolbox pg. 17</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/summoning">summoning</Link>); <strong>Level</strong> arcanist 1, magus 1, sorcerer 1, wizard 1<br/><strong>Casting Time</strong> 1 round<br/><strong>Components</strong> V, S<br/><strong>Range</strong> touch<br/><strong>Target</strong> spellbook touched<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>This spell sends a spellbook into a random but safe location on the Ethereal Plane, where it remains indefinitely. When you cast this spell, the target spellbook dissolves into quickly fading lines of energy and runes that reflect all of the spells stored within. Thereafter, you can retrieve the spellbook by concentrating as a standard action, causing it to reappear in your hands. You cannot cast this spell on another spellbook if you currently have a spellbook in the Ethereal Plane. No other creatures or objects accompany the spellbook you send away, and the duration of any spells currently affecting the spellbook continue normally.</p>
</>};
const _second_wind = {title: "Second Wind", jsx: <><h2 id="spell-second_wind-second-wind">Second Wind</h2>
<p><strong>Sources</strong> <Link to="/source/elemental_masters_handbook">Elemental Master's Handbook pg. 18</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/healing">healing</Link>) [<Link to="/spelldef/air">air</Link>]; <strong>Level</strong> antipaladin 3, cleric 3, hunter 3, inquisitor 3, oracle 3, paladin 3, ranger 3, warpriest 3<br/><strong>Casting Time</strong> 1 swift action or 1 immediate action; see text<br/><strong>Components</strong> V<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> instantaneous</p><p>You can cast this spell only when you have fewer than one-quarter of your total hit points. With a gasping utterance, you summon invigorating air to fill your lungs. You heal 2d8 points of damage + 1 point per caster level (maximum +10). You can cast this spell either as a swift action on your turn or as an immediate action when you are brought to below 0 hit points. If you do not breathe, you can't benefit from this spell.</p>
</>};
const _secret_chest = {hasJL:true,title: "Secret Chest", jsx: <><div className="jumpList" id="spell-secret_chest-jumplist"><h2>Jump to:</h2><ul><li><InnerLink toTop to="spell-secret_chest-secret-coffer">Secret Coffer</InnerLink></li><li><InnerLink toTop to="spell-secret_chest-secret-vault">Secret Vault</InnerLink></li></ul></div><h2 id="spell-secret_chest-secret-chest">Secret Chest</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 338</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/summoning">summoning</Link>); <strong>Level</strong> arcanist 5, mesmerist 5, occultist 5, psychic 5, sorcerer 5, spiritualist 5, witch 5, wizard 5<br/><strong>Casting Time</strong> 10 minutes<br/><strong>Components</strong> V, S, F (the chest and its replica)<br/><strong>Range</strong> see text<br/><strong>Target</strong> one chest and up to 1 cu. ft. of goods/caster level<br/><strong>Duration</strong> 60 days or until discharged<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>You hide a chest on the Ethereal Plane for as long as 60 days and can retrieve it at will. The chest can contain up to 1 cubic foot of material per caster level (regardless of the chest's actual size, which is about 3 feet by 2 feet by 2 feet). If any living creatures are in the chest, there is a 75% chance that the spell simply fails. Once the chest is hidden, you can retrieve it by concentrating (a standard action), and it appears next to you.</p>
<p>The chest must be exceptionally well crafted and expensive, constructed for you by master crafters. The cost of such a chest is never less than 5,000 gp. Once it is constructed, you must make a tiny replica (of the same materials and perfect in every detail) so that the miniature of the chest appears to be a perfect copy. (The replica costs 50 gp.) The chests are nonmagical and can be fitted with locks, wards, and so on, just as any normal chest can be.</p>
<p>To hide the chest, you cast the spell while touching both the chest and the replica. The chest vanishes into the Ethereal Plane. You need the replica to recall the chest. After 60 days, there is a cumulative chance of 5% per day that the chest is irretrievably lost. If the miniature of the chest is lost or destroyed, there is no way, even with a wish spell, that the large chest can be summoned back, although an extraplanar expedition might be mounted to find it.</p>
<p>Living things in the chest eat, sleep, and age normally, and they die if they run out of food, air, water, or whatever they need to survive.</p>
<h3 id="spell-secret_chest-secret-coffer" data-hash-target>Secret Coffer</h3>
<p><strong>Sources</strong> <Link to="/source/black_markets">Black Markets pg. 31</Link>, <Link to="/source/heroes_of_the_streets">Heroes of the Streets pg. 31</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/summoning">summoning</Link>); <strong>Level</strong> arcanist 3, sorcerer 3, witch 3, wizard 3<br/><strong>Casting Time</strong> 10 minutes<br/><strong>Components</strong> V, S, F (the chest and its replica)<br/><strong>Range</strong> see text<br/><strong>Target</strong> one small chest or coffer and up to 1 cu. ft. of goods<br/><strong>Duration</strong> 60 days or until discharged<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>This spell functions like secret chest, except the coffer is only 1 foot square and can contain only 1 cubic foot of goods, and the container can remain safely hidden on the Ethereal Plane for only 14 days before it risks becoming lost. The spell automatically fails if a living creature enters the coffer. The coffer used as a focus for secret coffer must cost at least 500 gp, and its replica costs 5 gp.</p>
<h3 id="spell-secret_chest-secret-vault" data-hash-target>Secret Vault</h3>
<p><strong>Sources</strong> <Link to="/source/black_markets">Black Markets pg. 31</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/summoning">summoning</Link>); <strong>Level</strong> arcanist 8, sorcerer 8, witch 8, wizard 8<br/><strong>Casting Time</strong> 10 minutes<br/><strong>Components</strong> V, S, F (the chest and its replica)<br/><strong>Range</strong> see text<br/><strong>Target</strong> one chamber and up to 10 cu. ft. of goods/caster level<br/><strong>Duration</strong> 360 days or until discharged<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>This spell functions like secret chest, except it affects a small structure, vault, or oversized chest. Living creatures within a secret vault don't cause the spell to fail. While the vault is stored on the Ethereal Plane, living creatures within the vault don't need to eat, drink, or breathe, but they can't leave the vault except via magic such as plane shift. The vault used as a focus for secret vault must cost at least 25,000 gp, and its replica costs 250 gp. A secret vault has only a 1% cumulative chance per day of becoming irretrievably lost after 360 days.</p>
<blockquote>
<p><em>Note: The original source does not mention a change in duration from <em>secret chest,</em> but the text implies a 360-day duration.</em></p>
</blockquote>
</>};
const _secret_page = {title: "Secret Page", jsx: <><h2 id="spell-secret_page-secret-page">Secret Page</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 338</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> arcanist 3, bard 3, mesmerist 3, occultist 3, red mantis assassin 3, skald 3, sorcerer 3, wizard 3<br/><strong>Casting Time</strong> 10 minutes<br/><strong>Components</strong> V, S, M (powdered herring scales and a vial of will-o'-wisp essence)<br/><strong>Range</strong> touch<br/><strong>Target</strong> page touched, up to 3 sq. ft. in size<br/><strong>Duration</strong> permanent<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>Secret page alters the contents of a page so that it appears to be something entirely different. The text of a spell can be changed to show another spell of equal or lower level known by the caster. This spell cannot be used to change a spell contained on a scroll, but it can be used to hide a scroll. Explosive runes or sepia snake sigil can be cast upon the secret page.</p>
<p>A comprehend languages spell alone cannot reveal a secret page's contents. You are able to reveal the original contents by speaking a special word. You can then peruse the actual page and return it to its secret page form at will. You can also remove the spell by double repetition of the special word. A detect magic spell reveals dim magic on the page in question but does not reveal its true contents. True seeing reveals the presence of the hidden material but does not reveal the contents unless cast in combination with comprehend languages. A secret page spell can be dispelled, and the hidden writings can be destroyed by means of an erase spell.</p>
</>};
const _secret_sign = {title: "Secret Sign", jsx: <><h2 id="spell-secret_sign-secret-sign">Secret Sign</h2>
<p><strong>Sources</strong> <Link to="/source/black_markets">Black Markets pg. 25</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/glamer">glamer</Link>); <strong>Level</strong> arcanist 2, bard 1, inquisitor 1, shaman 1, skald 1, sorcerer 2, witch 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a lemon peel)<br/><strong>Range</strong> touch<br/><strong>Target</strong> one creature or object<br/><strong>Duration</strong> 1 day/level<br/><strong>Saving Throw</strong> Will negates (object); <strong>Spell Resistance</strong> yes (object)</p><p>You invisibly inscribe a small mark or short message (no more than 25 words) on a creature or object, similar to the way arcane mark works. The sign can be no more than 6 inches across, and if it's a written message, it can be in any language you can read and write at the time of the spell's casting. As you cast the spell, you can define one auditory, olfactory, tangible, or visual criterion - such as all creatures wearing green bands on their left arms or only creatures who smell of lavender or only orcs - that allows designated creatures within 30 feet to see the secret sign.</p>
<p>Disguises and illusions that mimic the set criterion can fool this spell. Normal darkness doesn't conceal a visual trigger, but magical darkness or invisibility does. Auditory criteria (such as a password) and tangible criteria (such as pressing your hand against a specific object or wall) can be performed by anyone who learns of them. A secret sign cannot distinguish alignment, level, Hit Dice, or class except by external garb, but can differentiate apparent races, genders, and garments. See invisibility and invisibility purge reveal the sign, but glitterdust does not.</p>
<p>A caster of at least 10th level can make secret sign permanent on an object with a <Link to="/spell/permanency">permanency</Link> spell using 5,000 gp of diamond dust as a material component.</p>
</>};
const _secret_speech = {title: "Secret Speech", jsx: <><h2 id="spell-secret_speech-secret-speech">Secret Speech</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 240</Link>, <Link to="/source/pathfinder_17_a_memory_of_darkness">Pathfinder #17: A Memory of Darkness pg. 62</Link><br/><strong>School</strong> <Link to="/spelldef/divination">divination</Link>; <strong>Level</strong> arcanist 2, bard 1, cleric 2, inquisitor 1, oracle 2, shaman 2, skald 1, sorcerer 2, warpriest 2, wizard 2 (Calistria; see below)<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> 10 minutes/level<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> no (harmless)</p><p>This spell grants the target the ability to send secret messages embedded within normal speech. This is similar to the secret messages ability of the Bluff skill, but no check is needed; the speaker's intended recipient always understands the hidden message perfectly, but other listeners cannot perceive the message at all. The target can send only one message at a time, though it can send that message to multiple listeners. The secret message is considered to be in the same language the target is speaking, and intended recipients hear and understand both the actual speech and the secret message. The target can make itself understood as far as its voice carries.</p>
<p>For example, at a fancy noble's wedding, a jealous former suitor casts this spell on himself before making a speech. Everyone hears his glowing words of praise, but only his allies hear his secret message instructing them to attack the groom.</p>
<aside><p>Some spells are more common among the worshipers of a god. Worshipers of a spell's associated deity always treat the spell as common, and need not research it in order to prepare or learn it. This spell is available to members of other faiths, though some temples or religious organizations may proscribe the use of specific spells. -- <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 228</Link></p>
</aside></>};
const _secure_shelter = {title: "Secure Shelter", jsx: <><h2 id="spell-secure_shelter-secure-shelter">Secure Shelter</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 338</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/creation">creation</Link>); <strong>Level</strong> arcanist 4, bard 4, skald 4, sorcerer 4, witch 4, wizard 4<br/><strong>Casting Time</strong> 10 minutes<br/><strong>Components</strong> V, S, M (a chip of stone, sand, a drop of water, and a wood splinter)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Effect</strong> 20-ft.-square structure<br/><strong>Duration</strong> 2 hours/level (D)<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>You conjure a sturdy cottage or lodge made of material that is common in the area where the spell is cast. The floor is level, clean, and dry. The lodging resembles a normal cottage, with a sturdy door, two shuttered windows, and a small fireplace.</p>
<p>The shelter must be heated as a normal dwelling, and extreme heat adversely affects it and its occupants. The dwelling does, however, provide considerable security otherwise - it is as strong as a normal stone building, regardless of its material composition. The dwelling resists flames and fire as if it were stone. It is impervious to normal missiles (but not the sort cast by siege engines or giants).</p>
<p>The door, shutters, and even chimney are secure against intrusion, the former two being secured with arcane lock and the latter by an iron grate at the top and a narrow flue. In addition, these three areas are protected by an alarm spell. Finally, an unseen servant is conjured to provide service to you for the duration of the shelter.</p>
<p>The secure shelter contains crude furnishings-eight bunks, a trestle table, eight stools, and a writing desk.</p>
</>};
const _seducers_eyes = {title: "Seducer's Eyes", jsx: <><h2 id="spell-seducers_eyes-seducers-eyes">Seducer's Eyes</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 240</Link>, <Link to="/source/faiths_of_balance">Faiths of Balance pg. 28</Link><br/><strong>School</strong> <Link to="/spelldef/enchantment">enchantment</Link> (<Link to="/spelldef/charm">charm</Link>) [<Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> arcanist 2, bard 2, skald 2, sorcerer 2, witch 2, wizard 2 (Calistria; see below)<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 10 minutes/level (D)</p><p>You gain a bonus on Charisma-based skill checks equal to 1 + 1 for every 4 caster levels you possess (to a maximum of +5), but only when interacting with those who might conceivably find you sexually attractive. You do not gain this bonus against those you or your allies are attacking or threatening.</p>
<aside><p>Some spells are more common among the worshipers of a god. Worshipers of a spell's associated deity always treat the spell as common, and need not research it in order to prepare or learn it. This spell is available to members of other faiths, though some temples or religious organizations may proscribe the use of specific spells. -- <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 228</Link></p>
</aside></>};
const _see_alignment = {title: "See Alignment", jsx: <><h2 id="spell-see_alignment-see-alignment">See Alignment</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 243</Link><br/><strong>School</strong> <Link to="/spelldef/divination">divination</Link>; <strong>Level</strong> alchemist 1, arcanist 1, bard 1, investigator 1, psychic 1, skald 1, sorcerer 1, wizard 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (eye of newt)<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1/round per level</p><p>When you cast this spell, select a single alignment (such as lawful good or chaotic evil). Creatures of that alignment glow with a ghostly radiance while they are within your vision. Though you can see this radiance, other creatures cannot.</p>
<p>Spells and effects that obscure alignment, like undetectable alignment, also obscure the effects of this spell.</p>
</>};
const _see_beyond = {title: "See Beyond", jsx: <><h2 id="spell-see_beyond-see-beyond">See Beyond</h2>
<p><strong>Sources</strong> <Link to="/source/divine_anthology">Divine Anthology pg. 13</Link><br/><strong>School</strong> <Link to="/spelldef/divination">divination</Link> [<Link to="/spelldef/meditative">meditative</Link>]; <strong>Level</strong> arcanist 3, cleric 3, shaman 3, warpriest 3, witch 3, wizard 3<br/><strong>Casting Time</strong> 1 hour<br/><strong>Components</strong> V, M (soothing incense worth 300 gp)<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 24 hours or until discharged</p><p>You attune your mind and your sight to the hidden world of spirits. You gain a +5 circumstance bonus on Perception checks; this circumstance bonus increases to a +10 circumstance bonus on Perception checks to find invisible creatures or objects, incorporeal creatures or objects, or things that exist only on he Ethereal Plane. Additionally, at any time during the spell's duration, you can push your ethereal vision even further as a swift action. When you do, you can see through solid objects (as if using a ring of x-ray vision) for 5 rounds. After this time, the spell ends.</p>
</>};
const _see_invisibility = {title: "See Invisibility", jsx: <><h2 id="spell-see_invisibility-see-invisibility">See Invisibility</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 339</Link><br/><strong>School</strong> <Link to="/spelldef/divination">divination</Link>; <strong>Level</strong> adept 2, alchemist 2, arcanist 2, bloodrager 2, bard 3, inquisitor 2, investigator 2, mesmerist 3, occultist 2, psychic 2, skald 3, sorcerer 2, spiritualist 2, summoner 2, unchained summoner 2, witch 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (talc and powdered silver)<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 10 minutes/level (D)</p><p>You can see any objects or beings that are invisible within your range of vision, as well as any that are ethereal, as if they were normally visible. Such creatures are visible to you as translucent shapes, allowing you easily to discern the difference between visible, invisible, and ethereal creatures.</p>
<p>The spell does not reveal the method used to obtain invisibility. It does not reveal illusions or enable you to see through opaque objects. It does not reveal creatures who are simply hiding, concealed, or otherwise hard to see.</p>
<p>See invisibility can be made permanent with a <Link to="/spell/permanency">permanency</Link> spell.</p>
<h3 id="spell-see_invisibility-glimpse-the-hidden">Glimpse the Hidden</h3>
<p><strong>Sources</strong> <Link to="/source/potions_and_poisons">Potions and Poisons pg. 17</Link><br/><strong>School</strong> <Link to="/spelldef/divination">divination</Link>; <strong>Level</strong> alchemist 3, arcanist 3, inquisitor 3, investigator 3, sorcerer 3, summoner 3, unchained summoner 3, wizard 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a pinch of magnesium and platinum)<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> 1 round/level (D)<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>This spell functions as see invisibility, except as noted here. This spell cannot be made permanent.</p>
</>};
const _see_through_stone = {title: "See Through Stone", jsx: <><h2 id="spell-see_through_stone-see-through-stone">See Through Stone</h2>
<p><strong>Sources</strong> <Link to="/source/dwarves_of_golarion">Dwarves of Golarion pg. 25</Link><br/><strong>School</strong> <Link to="/spelldef/divination">divination</Link>; <strong>Level</strong> druid 4, hunter 3, ranger 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> concentration, up to 1 round/level (D)<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>You gain the ability to see through solid rock as if it were transparent glass. You may see through 1 foot of stone per caster level. You see within the stone as if you were looking at the area in normal light, even if there is no illumination, though low-light vision and darkvision have no effect on your ability to see through stone. Metal at least 1 inch thick or wood or dirt at least 3 feet thick blocks your vision.</p>
<p>The spell does not negate <Link to="/rule/concealment">concealment</Link> for those creatures hiding behind stone objects (the stone is still an obstacle to your attacks).</p>
</>};
const _seed_spies = {title: "Seed Spies", jsx: <><h2 id="spell-seed_spies-seed-spies">Seed Spies</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 14</Link><br/><strong>School</strong> <Link to="/spelldef/divination">divination</Link>; <strong>Level</strong> arcanist 3, druid 2, hunter 2, occultist 2, ranger 2, shaman 3, sorcerer 3, witch 3, wizard 3<br/><strong>Casting Time</strong> 1 round<br/><strong>Components</strong> V, S, M (a drop of honey)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Effect</strong> up to one insect spy/4 levels<br/><strong>Duration</strong> 10 minutes/level (D)<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><blockquote>
<p><em><Link to="/race/gathlain">Gathlains</Link> have access to the following spell.</em></p>
</blockquote>
<p>This spell functions as <Link to="/spell/insect_spies">insect spies</Link>, except it creates wafting seeds with magical intellect instead of insects. The seeds can hear but not see. They fly at a speed of 10 feet (good maneuverability), but they can't crawl or climb, although they can cling to rough, soft, or sticky creatures or surfaces.</p>
</>};
const _seeds_of_influence = {title: "Seeds of Influence", jsx: <><h2 id="spell-seeds_of_influence-seeds-of-influence">Seeds of Influence</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_intrigue">Inner Sea Intrigue pg. 62</Link><br/><strong>School</strong> <Link to="/spelldef/enchantment">enchantment</Link> (<Link to="/spelldef/compulsion">compulsion</Link>) [<Link to="/spelldef/emotion">emotion</Link>, <Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> arcanist 4, bard 3, medium 3, mesmerist 3, psychic 4, skald 3, sorcerer 4, witch 4, wizard 4<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> S, M (a rose)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Targets</strong> one creature<br/><strong>Duration</strong> 1 hour/level (D)<br/><strong>Saving Throw</strong> Will negates; <strong>Spell Resistance</strong> yes</p><p>You leave a magical trace in the mind of a creature with an attitude of at least indifferent toward you. The target takes a cumulative -2 penalty on its Will save to negate the spell for each step by which its attitude is better than indifferent.</p>
<p>The target takes a -2 penalty on saving throws against divination spells you cast. You can target that creature with mind-affecting spells of a spell level lower than seeds of influence as if those spells were modified by <Link to="/feat/enlarge_spell">Enlarge Spell</Link> (the modified spell doesn't take longer to cast and doesn't use a higher-level spell slot). Whenever the target succeeds at a saving throw against a divination or mind-affecting spell you cast, seeds of influence ends for that target. A creature can be subject to only one seeds of influence spell at a time; later castings of seeds of influence remove any previous casting.</p>
<h3 id="spell-seeds_of_influence-greater-seeds-of-influence">Greater Seeds of Influence</h3>
<p><strong>Sources</strong> <Link to="/source/inner_sea_intrigue">Inner Sea Intrigue pg. 62</Link><br/><strong>School</strong> <Link to="/spelldef/enchantment">enchantment</Link> (<Link to="/spelldef/compulsion">compulsion</Link>) [<Link to="/spelldef/emotion">emotion</Link>, <Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> arcanist 7, bard 5, medium 4, mesmerist 5, psychic 7, skald 5, sorcerer 7, witch 7, wizard 7<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> S, M (a rose)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Targets</strong> one creature<br/><strong>Duration</strong> 1 day/level (D)<br/><strong>Saving Throw</strong> Will negates; <strong>Spell Resistance</strong> yes</p><p>This spell functions as seeds of influence, except that if the target is protected by a spell that grants immunity, spell resistance, or a saving throw bonus against a divination or mind-affecting spell you cast on the target, you can attempt caster level checks to dispel each such effect before applying the effects of those protections against the spell. The DC of the caster level check to dispel each effect is equal to 11 + the effect's caster level. Such spells cast on the target while greater seeds of influence is active grant no protection against greater seeds of influence.</p>
</>};
const _seek_shelter = {title: "Seek Shelter", jsx: <><h2 id="spell-seek_shelter-seek-shelter">Seek Shelter</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_intrigue">Inner Sea Intrigue pg. 62</Link><br/><strong>School</strong> <Link to="/spelldef/enchantment">enchantment</Link> (<Link to="/spelldef/compulsion">compulsion</Link>) [<Link to="/spelldef/fear">fear</Link>, <Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> arcanist 5, bard 4, cleric 5, inquisitor 4, mesmerist 4, oracle 5, psychic 5, skald 4, sorcerer 5, summoner 4, unchained summoner 4, warpriest 5, witch 5, wizard 5<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Targets</strong> all non-hostile creatures with 4 or fewer HD in a 30-ft.-radius spread<br/><strong>Duration</strong> 1 hour/level (D)<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes</p><p>You send an empathic urge to seek safety both as fast as possible and in an orderly fashion, and to remain in such secure locations for the duration of the spell. Targets with 5 or more Hit Dice are unaffected. When you cast the spell, you can designate a fortified location - either general (such as "indoors") or specific (such as "the local garrison") - for the targets to attempt to reach. If you do not specify a location for the targets to retreat to, they attempt to find safety to the best of their ability. Affected creatures defend themselves normally but attack only if provoked.</p>
</>};
const _seek_thoughts = {title: "Seek Thoughts", jsx: <><h2 id="spell-seek_thoughts-seek-thoughts">Seek Thoughts</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 242</Link><br/><strong>School</strong> <Link to="/spelldef/divination">divination</Link> [<Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> alchemist 3, arcanist 3, bard 3, inquisitor 3, investigator 3, medium 2, mesmerist 3, occultist 3, psychic 2, skald 3, sorcerer 3, spiritualist 3, summoner 3, unchained summoner 3, witch 3, wizard 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a handful of copper coins)<br/><strong>Range</strong> 40 ft.<br/><strong>Area</strong> 40-ft.-radius emanation centered on you<br/><strong>Duration</strong> concentration, up to 1 minute/level<br/><strong>Saving Throw</strong> Will negates; <strong>Spell Resistance</strong> no</p><p>Similar to detect thoughts, seek thoughts allows you to sift through the surface thoughts of those around you. You may scan for either the answer to a simple question (such as "Where is the hidden lair of the wererats"?) or for information on a general topic (such as the beliefs of an evil cult). You detect the number of creatures who are thinking about this question or topic within range, as well as their location if they are visible to you. Seek thoughts does not let you read actual surface thoughts, only if a given creature is thinking about the topic you are concentrating on. A successful Will save prevents you from sensing a creature's thoughts for the duration of the spell.</p>
<p>You can maintain concentration on seek thoughts while you engage in normal conversation, allowing you to ask leading questions about topics of interest. A creature conversing with you while you concentrate can notice that you are distracted with a successful DC 25 Sense Motive check.</p>
</>};
const _seeming = {title: "Seeming", jsx: <><h2 id="spell-seeming-seeming">Seeming</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 339</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/glamer">glamer</Link>); <strong>Level</strong> arcanist 5, bard 5, medium 4, mesmerist 5, occultist 5, psychic 5, skald 5, sorcerer 5, wizard 5<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Targets</strong> one creature per two levels, no two of which can be more than 30 ft. apart<br/><strong>Duration</strong> 12 hours (D)<br/><strong>Saving Throw</strong> Will negates or Will disbelief (if interacted with); <strong>Spell Resistance</strong> yes or no; see text</p><p>This spell functions like disguise self, except that you can change the appearance of other people as well. Affected creatures resume their normal appearances if slain. Unwilling targets can negate the spell's effect on them by making Will saves or with spell resistance.</p>
</>};
const _seers_bane = {title: "Seer's Bane", jsx: <><h2 id="spell-seers_bane-seers-bane">Seer's Bane</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_102_breaking_the_bones_of_hell">Pathfinder #102: Breaking the Bones of Hell pg. 75</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link>; <strong>Level</strong> cleric 6, inquisitor 6, oracle 6, warpriest 6<br/><strong>Casting Time</strong> 1 round<br/><strong>Components</strong> V, S<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature or object touched<br/><strong>Duration</strong> 1 hour/level<br/><strong>Saving Throw</strong> Will negates (object, harmless); <strong>Spell Resistance</strong> yes (object, harmless)</p><blockquote>
<p><em>Priests of <Link to="/faith/mephistopheles">Mephistopheles</Link> have access to the following spell.</em></p>
</blockquote>
<p>This spell functions as <Link to="/spell/nondetection">nondetection</Link>, except that those who cast divination spells targeting the warded creature or item must succeed on a caster level check (DC = 15 + your caster level). If the caster of the divination fails, deadly magical feedback strikes at him, dealing 1d6 points of electricity damage per 2 caster levels you have (maximum 10d6 at 20th level).</p>
<p>Alternatively, if you cast bestow curse, chaos hammer, contagion, holy smite, order's wrath, poison, or unholy blight in the round immediately following seer's bane, you can replace the spell's damaging effect with the effects of that second spell (the divination's caster - and potentially those around him - save as normal for the modifying spell).</p>
</>};
const _seismic_fissure = {title: "Seismic Fissure", jsx: <><h2 id="spell-seismic_fissure-seismic-fissure">Seismic Fissure</h2>
<p><strong>Sources</strong> <Link to="/source/wilderness_origins">Wilderness Origins pg. 27</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link> [<Link to="/spelldef/earth">earth</Link>]; <strong>Level</strong> druid 7, shaman 7<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> long (400 ft. + 40 ft./level)<br/><strong>Effect</strong> 10-ft.-by-80-ft. fissure in the earth, 40 ft. deep<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Reflex negates; <strong>Spell Resistance</strong> no</p><p>With a thrust of tectonic energy, you split the earth. Each creature standing in the area where the fissure opens must succeed at a Reflex saving throw to avoid falling into the rift. Those standing adjacent to the fissure when it is created must succeed at a Reflex save or be knocked prone by tremors. This spell is effective only when cast on an area of dirt, earth, sand, or stone.</p>
</>};
const _selective_invisibility = {title: "Selective Invisibility", jsx: <><h2 id="spell-selective_invisibility-selective-invisibility">Selective Invisibility</h2>
<p><strong>Sources</strong> <Link to="/source/dirty_tactics_toolbox">Dirty Tactics Toolbox pg. 31</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/glamer">glamer</Link>); <strong>Level</strong> alchemist 3, antipaladin 3, arcanist 3, bard 3, inquisitor 3, investigator 3, magus 3, skald 3, sorcerer 3, summoner 3, wizard 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M/DF (three translucent pebbles)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> you and one other creature<br/><strong>Duration</strong> 1 round/level (D)<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> yes</p><p>Upon casting this spell, you turn invisible, as per the <Link to="/spell/invisibility">invisibility</Link> spell, and you choose a second target. That creature can still see you as though you were not invisible, and you can attack that creature without ending the invisibility effect on you. However, if you attack any other creature, this spell ends. If you cast this spell multiple times, you can attack any of the affected creatures without ending the spell.</p>
</>};
const _semblance_of_flesh = {title: "Semblance of Flesh", jsx: <><h2 id="spell-semblance_of_flesh-semblance-of-flesh">Semblance of Flesh</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_86_lords_of_rust">Pathfinder #86: Lords of Rust pg. 75</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/glamer">glamer</Link>); <strong>Level</strong> arcanist 2, cleric 2, oracle 2, sorcerer 2, warpriest 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> touch<br/><strong>Target</strong> construct touched<br/><strong>Duration</strong> 10 minutes/level (D)</p><blockquote>
<p><em>Clerics of <Link to="/faith/brigh">Brigh</Link> have access to the following spell.</em></p>
</blockquote>
<p>You make the target construct appear to be a living creature of flesh and bone, regardless of its actual materials. You can make it seem 1 foot shorter or taller, and appear thin, fat, or anywhere in between. Its bodily configuration does not change; for example, a centaur-like construct looks like a centaur rather than a human. The extent of the apparent change (such as flesh color, hair color, apparent age, and so on) is up to you.</p>
<p>The spell does not provide the abilities or mannerisms of the chosen form, nor does it alter the perceived tactile or audible properties of the construct. If you use this spell to create a disguise, the construct gains a +10 bonus on the Disguise check. A creature that interacts with the glamer receives a Will save to recognize it as an illusion.</p>
</>};
const _sending = {hasJL:true,title: "Sending", jsx: <><div className="jumpList" id="spell-sending-jumplist"><h2>Jump to:</h2><ul><li><InnerLink toTop to="spell-sending-mythic_sending">Mythic Sending</InnerLink></li><li><InnerLink toTop to="spell-sending-word-of-beckoning">Word of Beckoning</InnerLink></li></ul></div><h2 id="spell-sending-sending">Sending</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 339</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link>; <strong>Level</strong> alchemist 5, arcanist 5, cleric 4, inquisitor 4, investigator 5, medium 3, mesmerist 3, occultist 4, oracle 4, psychic 4, shaman 4, sorcerer 5, spiritualist 5, summoner 4, unchained summoner 5, warpriest 4, wizard 5<br/><strong>Casting Time</strong> 10 minutes<br/><strong>Components</strong> V, S, M/DF (fine copper wire)<br/><strong>Range</strong> see text<br/><strong>Target</strong> one creature<br/><strong>Duration</strong> 1 round; see text<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>You contact a particular creature with which you are familiar and send a short message of 25 words or less to the subject. The subject recognizes you if it knows you. It can answer in like manner immediately. A creature with an Intelligence score as low as 1 can understand the sending, though the subject's ability to react is limited as normal by its Intelligence. Even if the sending is received, the subject is not obligated to act upon it in any manner.</p>
<p>If the creature in question is not on the same plane of existence as you are, there is a 5% chance that the sending does not arrive. (Local conditions on other planes may worsen this chance considerably.)</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="spell-sending--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col" id="spell-sending-mythic_sending" data-hash-target>Mythic Sending</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 107</Link></p>
<p>You can contact a number of additional creatures equal to your tier. Each creature must receive the same message, and can communicate back only to you.</p>
<p><em>Augmented (3rd):</em> If you expend two uses of mythic power, you can send the message to unfamiliar creatures (using the same number of creatures as non-augmented mythic sending). You must either describe the intended recipients in general or specific terms (such as "orcs," "the queen of this country," or "left-handed half-elven males") or specify restrictions such as range, creature type, and alignment (such as "all good-aligned humanoids in the castle on the hill"). If a greater number of creatures meet your description than the maximum number you can send to, the closest ones to you receive the message.</p>
</td></tr></tbody></table></ScrollContainer></div><h3 id="spell-sending-word-of-beckoning" data-hash-target>Word of Beckoning</h3>
<p><strong>Sources</strong> <Link to="/source/pathfinder_131_the_reapers_right_hand">Pathfinder #131: The Reaper's Right Hand pg. 72</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/teleportation">teleportation</Link>); <strong>Level</strong> arcanist 7, psychic 7, sorcerer 7, wizard 7<br/><strong>Casting Time</strong> 10 minutes<br/><strong>Components</strong> V, S, M/DF (fine copper wire)<br/><strong>Range</strong> see text<br/><strong>Target</strong> one creature<br/><strong>Duration</strong> 1 round; see text<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>This spell functions like sending, except the subject also receives knowledge of a command word that, when spoken, summons you to the open space nearest to the subject. The subject must speak the command word within 1 round of knowing it to summon you, although the subject isn't obligated to speak it. You can be transported any distance within a plane but cannot travel between planes. You can bring along objects as long as their weight doesn't exceed your maximum load. You may also bring one additional willing Medium or smaller creature (carrying gear or objects up to its maximum load) or its equivalent per three caster levels. A Large creature counts as two Medium creatures, a Huge creature counts as four Medium creatures, and so forth. All creatures to be transported must be in contact with one another, and at least one of those creatures must be in contact with you.</p>
</>};
const _sense_fear = {title: "Sense Fear", jsx: <><h2 id="spell-sense_fear-sense-fear">Sense Fear</h2>
<p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 127</Link><br/><strong>School</strong> <Link to="/spelldef/divination">divination</Link>; <strong>Level</strong> antipaladin 1, bloodrager 1, cleric 2, druid 2, hunter 2, inquisitor 2, medium 1, mesmerist 2, occultist 2, oracle 2, psychic 2, ranger 2, shaman 2, spiritualist 2, witch 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M/DF (a patch of fur)<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 10 minutes/level (D)</p><p>You sense the fear of those nearby, feeling it in the air around you. You can detect <Link to="/rule/lesser_fear_and_greater_fear">spooked, shaken, scared, frightened, panicked, terrified, and horrified</Link> creatures within 30 feet, and you immediately know what level of fear they are experiencing. You determine the creatures' approximate direction from you, though you do not sense a given creature's identity or know which squares the creatures occupy. If you're within 5 feet of a creature whose fear you sense, you pinpoint that creature's location, as if using blindsense.</p>
</>};
const _sense_madness = {title: "Sense Madness", jsx: <><h2 id="spell-sense_madness-sense-madness">Sense Madness</h2>
<p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 127</Link><br/><strong>School</strong> <Link to="/spelldef/divination">divination</Link>; <strong>Level</strong> cleric 2, inquisitor 2, medium 2, occultist 2, oracle 2, paladin 2, psychic 2, warpriest 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> creatures in range (see text)<br/><strong>Duration</strong> concentration, up to 1 round/level<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>You can sense the presence of mental disturbance in creatures within range, focusing your detection on one creature each round. If the target is currently suffering from any form of <Link to="/rule/madness">madness</Link> or addiction, has total sanity damage greater than or equal to its <Link to="/rule/sanity_score_edge_and_thresholds">sanity edge</Link>, or is under a magical compulsion that could be detected by <Link to="/spell/detect_magic">detect magic</Link>, you can detect the presence of such a disturbance on the first round of concentration.</p>
<p>If you concentrate on the same creature for an additional round, you learn if the creature's total sanity damage is greater than or equal to its sanity edge, and you can attempt a Sense Motive check against a DC equal to 10 + the save DC of the target's madness or addiction to determine the exact nature of a madness or addiction. Additionally, you can attempt a Spellcraft check with a DC equal to 11 + the caster level of the compulsion against each magical compulsion currently affecting the target that could be detected by detect magic. If successful, you can identify the specific spell affecting the target. You gain a +4 bonus on your Spellcraft check if the effect is confusion, insanity, or a similar effect that explicitly causes madness or insanity. If you successfully identify such an effect with sense madness, the insights provided by this spell grant you a +1 circumstance bonus on your next caster level check in the following 1 minute made to counter, dispel, or remove that specific effect. After attempting a check to identify a madness, addiction, or compulsion, you can't attempt that check against the same creature again, even if you concentrate on the creature again.</p>
</>};
const _sense_spirit_magic = {title: "Sense Spirit Magic", jsx: <><h2 id="spell-sense_spirit_magic-sense-spirit-magic">Sense Spirit Magic</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 191</Link><br/><strong>School</strong> <Link to="/spelldef/divination">divination</Link>; <strong>Level</strong> shaman 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 24 hours<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>You gain greater sensitivity to magic associated with your primary spirit and wandering spirits (any spells on the spirit magic spell lists for these spirits, as well as spell-like abilities that duplicate the effects of those spells). You gain a +10 circumstance bonus on Spellcraft checks to identify these spells if they are cast within the area, and a +2 circumstance bonus on saving throws to resist the effects of such spells. If any of these spells require an attack roll, you are never considered flat-footed against such attacks.</p>
</>};
const _sense_vitals = {title: "Sense Vitals", jsx: <><h2 id="spell-sense_vitals-sense-vitals">Sense Vitals</h2>
<p><strong>Sources</strong> <Link to="/source/dirty_tactics_toolbox">Dirty Tactics Toolbox pg. 31</Link><br/><strong>School</strong> <Link to="/spelldef/divination">divination</Link>; <strong>Level</strong> antipaladin 2, arcanist 2, bard 2, hunter 2, ranger 2, skald 2, sorcerer 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a drop of blood)<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 round/level</p><p>This spell makes your eyes shine blood red and allows you to see the vital areas and weak points of creatures within 30 feet of you as a warm glow. This allows you to use any manufactured weapon to make sneak attacks, as the rogue ability of the same name, dealing an additional 1d6 points of damage; this additional damage increases by 1d6 for every 3 caster levels you possess beyond 3rd, to a maximum of +5d6 at 15th level. This additional damage stacks with other sources of precision damage.</p>
</>};
const _sensory_amplifier = {title: "Sensory Amplifier", jsx: <><h2 id="spell-sensory_amplifier-sensory-amplifier">Sensory Amplifier</h2>
<p><strong>Sources</strong> <Link to="/source/occult_origins">Occult Origins pg. 29</Link><br/><strong>School</strong> <Link to="/spelldef/divination">divination</Link> [<Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> druid 4, hunter 4, medium 2, mesmerist 3, psychic 3, witch 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> S<br/><strong>Range</strong> personal<br/><strong>Area</strong> 10-ft.-radius emanation centered on you<br/><strong>Duration</strong> 1 round/level (D)<br/><strong>Saving Throw</strong> Will negates; <strong>Spell Resistance</strong> yes</p><p>You open the minds of all creatures near you and enhance their sensory receptors. All living creatures other than you in the area gain a +5 bonus on Perception checks. Sighted creatures gain low-light vision, and creatures with a sense of smell gain <Link to="/umr/scent">scent</Link>. In addition, the first time each round that a creature in the area takes damage, it takes an additional 2d6 points of damage of the same type. Despite being within the area, the caster does not take this extra damage.</p>
</>};
const _sensory_overload = {title: "Sensory Overload", jsx: <><h2 id="spell-sensory_overload-sensory-overload">Sensory Overload</h2>
<p><strong>Sources</strong> <Link to="/source/psychic_anthology">Psychic Anthology pg. 11</Link><br/><strong>School</strong> <Link to="/spelldef/enchantment">enchantment</Link> (<Link to="/spelldef/compulsion">compulsion</Link>) [<Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> arcanist 2, psychic 2, sorcerer 2, witch 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> 1 creature<br/><strong>Duration</strong> 1 round/level<br/><strong>Saving Throw</strong> Will negates (see text); <strong>Spell Resistance</strong> yes</p><p>You overload the target creature's senses, making it difficult for the target to concentrate. For the duration of the effect, the target must succeed at a Will save at the same DC as the original effect to perform any standard or full-round action. On a failure, the creature loses the action that triggered the saving throw. If successful, the creature is able to take the action, but this spell effect is not negated.</p>
</>};
const _sentry_skull = {title: "Sentry Skull", jsx: <><h2 id="spell-sentry_skull-sentry-skull">Sentry Skull</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 143</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link> [<Link to="/spelldef/evil">evil</Link>]; <strong>Level</strong> antipaladin 1, arcanist 2, cleric 2, oracle 2, sorcerer 2, warpriest 2, witch 2, wizard 2<br/><strong>Casting Time</strong> 1 hour<br/><strong>Components</strong> V, S, M (an onyx gem worth at least 10 gp)<br/><strong>Range</strong> touch<br/><strong>Target</strong> severed head touched<br/><strong>Duration</strong> permanent (d); see text<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><blockquote>
<p><em><Link to="/race/orc">Orcs</Link> have access to the following spell.</em></p>
</blockquote>
<p>You restore the senses to the severed head of a humanoid or monstrous humanoid killed within the past 24 hours, creating a grisly sentinel. The head must be affixed to a pole, spear, tree branch, or other stable object, and the spell ends if the head or its object is moved. The head has darkvision 60 feet and low-light vision, can swivel in place to look in any direction, and has a +5 bonus on Perception checks.</p>
<p>If you are within 30 feet of the head, as a standard action you can shift your senses to it, seeing and hearing from its location and gaining the benefit of its darkvision and low-light vision, and you may use its Perception skill instead of your own. While your senses are in the severed head, your body is blind and deaf until you spend a free action to shift your senses back to your own body.</p>
<p>When you create the head, you can imprint it with a single triggering condition, similar to <Link to="/spell/magic_mouth">magic mouth</Link>. Once this triggering condition is set, it can never be changed. If you are within 30 feet of the head, you immediately know if it is triggered (if you have multiple active sentry skulls, you also know which one was triggered). This wakens you from normal sleep but does not otherwise disturb your concentration. For example, you could have a sentry skull alert you if any humanoid comes into view, if a particular rival approaches, if your guard animal is killed, and so on, as long as it occurs where the severed head can see it.</p>
<p>This spell does not give the head any ability to speak, think, or take any kind of action other than to turn itself, though it is a suitable target for other spells such as magic mouth.</p>
</>};
const _sepia_snake_sigil = {title: "Sepia Snake Sigil", jsx: <><h2 id="spell-sepia_snake_sigil-sepia-snake-sigil">Sepia Snake Sigil</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 339</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/creation">creation</Link>) [<Link to="/spelldef/force">force</Link>]; <strong>Level</strong> arcanist 3, bard 3, occultist 3, skald 3, sorcerer 3, witch 3, wizard 3<br/><strong>Casting Time</strong> 10 minutes<br/><strong>Components</strong> V, S, M (powdered amber worth 500 gp and a snake scale)<br/><strong>Range</strong> touch<br/><strong>Target</strong> one touched book or written work<br/><strong>Duration</strong> permanent or until discharged; until released or 1d4 days + 1 day/level; see text<br/><strong>Saving Throw</strong> Reflex negates; <strong>Spell Resistance</strong> no</p><p>You cause a small symbol to appear in the text of a written work. The text containing the symbol must be at least 25 words long. When anyone reads the text containing the symbol, the sepia snake sigil springs into being, transforming into a large sepia serpent that strikes at the reader, provided there is line of effect between the symbol and the reader.</p>
<p>Simply seeing the enspelled text is not sufficient to trigger the spell; the subject must deliberately read it. The target is entitled to a save to evade the snake's strike. If it succeeds, the sepia snake dissipates in a flash of brown light accompanied by a puff of dun-colored smoke and a loud noise. If the target fails its save, it is engulfed in a shimmering amber field of force and immobilized until released, either at your command or when 1d4 days + 1 day per caster level have elapsed.</p>
<p>While trapped in the amber field of force, the subject does not age, breathe, grow hungry, sleep, or regain spells. It is preserved in a state of suspended animation, unaware of its surroundings. It can be damaged by outside forces (and perhaps even killed), since the field provides no protection against physical injury. However, a dying subject does not lose hit points or become stable until the spell ends.</p>
<p>The hidden sigil cannot be detected by normal observation, and <Link to="/spell/detect_magic">detect magic</Link> reveals only that the entire text is magical.</p>
<p>A <Link to="/spell/dispel_magic">dispel magic</Link> can remove the sigil. An <Link to="/spell/erase">erase</Link> spell destroys the entire page of text.</p>
<p>Sepia snake sigil can be cast in combination with other spells that hide or garble text, such as <Link to="/spell/secret_page">secret page</Link>.</p>
</>};
const _sequester = {title: "Sequester", jsx: <><h2 id="spell-sequester-sequester">Sequester</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 340</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link>; <strong>Level</strong> arcanist 7, psychic 7, sorcerer 7, summoner 5, unchained summoner 6, wizard 7<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a basilisk eyelash and gum arabic)<br/><strong>Range</strong> touch<br/><strong>Target</strong> one willing creature or object (up to a 2-ft. cube/level) touched<br/><strong>Duration</strong> 1 day/level (D)<br/><strong>Saving Throw</strong> none or Will negates (object); <strong>Spell Resistance</strong> no or yes (object)</p><p>When cast, this spell prevents divination spells from detecting or locating the target and also renders the affected target invisible (as the <Link to="/spell/invisibility">invisibility</Link> spell). The spell does not prevent the subject from being discovered through tactile means or through the use of devices. Creatures affected by sequester become comatose and are effectively in a state of suspended animation until the spell ends.</p>
<p><em>Note:</em> The Will save prevents an attended or magical object from being sequestered. There is no save to see the sequestered creature or object or to detect it with a divination spell.</p>
</>};
const _sequester_thoughts = {title: "Sequester Thoughts", jsx: <><h2 id="spell-sequester_thoughts-sequester-thoughts">Sequester Thoughts</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_society_field_guide">Pathfinder Society Field Guide pg. 58</Link><br/><strong>School</strong> <Link to="/spelldef/enchantment">enchantment</Link> (<Link to="/spelldef/compulsion">compulsion</Link>) [<Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> arcanist 5, bard 3, skald 3, sorcerer 5, wizard 5<br/><strong>Casting Time</strong> 10 minutes<br/><strong>Components</strong> V, S, M (a gemstone worth at least 500 gp)<br/><strong>Range</strong> personal<br/><strong>Target</strong> one willing creature<br/><strong>Duration</strong> permanent until discharged (see text)</p><p>Sequester thoughts allows you to erase a creature's memory of either an event lasting not more than 1 minute per caster level or all of its knowledge about a single topic (using the GM's discretion as to what constitutes a single topic). For example, you could erase a single battle from a creature's memory, or all knowledge of a plot to assassinate a king. The memories you remove are stored within the gem used at the time of casting. If the gem is shattered, the memories return to the creature as long as the two are within 30 feet of each other. Once sequester thoughts has been cast, the spell remains active on the gem and can be dispelled (which shatters it). No portion of the spell remains active on the target creature, and the target does not radiate magic as a consequence of the spell, nor can its memories be returned by dispelling the creature or subjecting it to antimagic. If the gem is shattered or dispelled out of range from the creature, the thoughts sequestered within are forever lost save by the use of <Link to="/spell/wish">wish</Link>, <Link to="/spell/miracle">miracle</Link>, or the like.</p>
<p>Sequester thoughts protects against <Link to="/spell/detect_thoughts">detect thoughts</Link>, <Link to="/spell/zone_of_truth">zone of truth</Link>, <Link to="/spell/discern_lies">discern lies</Link>, and similar spells where the memories removed are concerned, though careful questioning may reveal the gaps in the creature's memory, or that it has been affected by the spell. Note that the creature itself does not remember any details of what memories were removed until the gem is broken.</p>
</>};
const _serenity = {title: "Serenity", jsx: <><h2 id="spell-serenity-serenity">Serenity</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 236</Link><br/><strong>School</strong> <Link to="/spelldef/enchantment">enchantment</Link> (<Link to="/spelldef/compulsion">compulsion</Link>) [<Link to="/spelldef/emotion">emotion</Link>, <Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> arcanist 6, bard 4, cleric 5, mesmerist 4, oracle 5, psychic 5, skald 4, sorcerer 6, warpriest 5, wizard 6<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Targets</strong> one creature/level, no two of which can be more than 30 ft. apart<br/><strong>Duration</strong> 1 round/level<br/><strong>Saving Throw</strong> Will negates; <strong>Spell Resistance</strong> yes</p><p>You fill the targets' minds with feelings of tranquility. Those attempting to commit violence become stricken with wracking pain and take 3d6 points of nonlethal damage each round they attempt to harm another creature. If attacked, affected individuals can defend themselves and may participate in combat by using <Link to="/feat/combat_expertise">Combat Expertise</Link>, fighting defensively, or taking the total defense action without triggering the spell's nonlethal damage.</p>
</>};
const _serrens_armor_lock = {title: "Serren's Armor Lock", jsx: <><h2 id="spell-serrens_armor_lock-serrens-armor-lock">Serren's Armor Lock</h2>
<p><strong>Sources</strong> <Link to="/source/knights_of_the_inner_sea">Knights of the Inner Sea pg. 29</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> arcanist 3, magus 2, red mantis assassin 3, sorcerer 3, witch 3, wizard 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a pinch of rust)<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Target</strong> one armored creature<br/><strong>Duration</strong> 1 round/level (D)<br/><strong>Saving Throw</strong> Reflex partial, see text; <strong>Spell Resistance</strong> yes</p><p>Upon pointing at an armored foe, you cause all of the joints of the target's armor to stiffen as otherworldly chains wrap around the target. On a failed Reflex save, a target in heavy metal armor becomes staggered. A target in light or medium metal armor instead becomes entangled. Targets wearing no armor or nonmetallic armor are unaffected. If the target is wearing heavy metal armor and succeeds at its Reflex save, it becomes entangled instead of staggered; a target in light or medium metal armor that succeeds at its saving throw is unaffected by the spell.</p>
</>};
const _serrens_swift_girding = {title: "Serren's Swift Girding", jsx: <><h2 id="spell-serrens_swift_girding-serrens-swift-girding">Serren's Swift Girding</h2>
<p><strong>Sources</strong> <Link to="/source/knights_of_the_inner_sea">Knights of the Inner Sea pg. 29</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> arcanist 1, magus 1, paladin 1, red mantis assassin 1, sorcerer 1, wizard 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (the armor to be worn)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one willing creature/level<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> yes</p><p>With a sweep of your hand, you select a number of targets and the same number of suits of armor. The targets of this spell are immediately clad in the armor that you choose. The subjects of the spell must be capable of wearing the chosen armor, cannot be wearing other armor, and must be able to properly fit into the chosen armor. The chosen armor must be empty and cannot be currently worn by another creature (thus you cannot move armor from one wearer to another with this spell). Creatures armored with this spell are considered to have donned the armor properly.</p>
</>};
const _sessile_spirit = {title: "Sessile Spirit", jsx: <><h2 id="spell-sessile_spirit-sessile-spirit">Sessile Spirit</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 185</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link>; <strong>Level</strong> cleric 5, inquisitor 4, medium 2, occultist 3, oracle 5, shaman 4, spiritualist 3, warpriest 5, witch 5<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Target</strong> one creature or object (see text)<br/><strong>Duration</strong> 1 round/level (D)<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes</p><p>You reach into the target creature and cause that spirits within to become dormant and inactive. If the target is a medium with a spirit inhabiting its body or a spiritualist with a phantom inhabiting its consciousness (or a member of another class using the spirit or phantom class features), a failed save renders that spirit or phantom powerless, suppressing any benefits the spirit or phantom normally provides to its host, including bonus feats and spells known.</p>
<p>If a spirit within the target is a creature using a possession effect, including possess object, possession, or a ghost's malevolence, the spell targets the possessing creature rather than the creature it inhabits. On a failed save, the possessing spirit isn't exorcised from the target but is dazed for the duration of the spell.</p>
</>};
const _severed_fate = {title: "Severed Fate", jsx: <><h2 id="spell-severed_fate-severed-fate">Severed Fate</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 324</Link><br/><strong>School</strong> <Link to="/spelldef/enchantment">enchantment</Link>; <strong>Level</strong> cleric 3, oracle 3, warpriest 3, witch 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one living creature<br/><strong>Duration</strong> 10 minutes/level<br/><strong>Saving Throw</strong> Will negates; <strong>Spell Resistance</strong> yes</p><p>You curse the target, preventing it from drawing upon the powers of destiny. The target is shaken and cannot use hero points for the duration of the spell. This effect can be removed by <Link to="/spell/dispel_magic">dispel magic</Link>, <Link to="/spell/remove_curse">remove curse</Link>, or other similar effects.</p>
</>};
const _shackle = {title: "Shackle", jsx: <><h2 id="spell-shackle-shackle">Shackle</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_guide">Adventurer's Guide pg. 99</Link>, <Link to="/source/path_of_the_hellknight">Path of the Hellknight pg. 61</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/creation">creation</Link>); <strong>Level</strong> arcanist 2, cleric 2, hunter 2, inquisitor 2, oracle 2, ranger 2, sorcerer 2, warpriest 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> touch<br/><strong>Effect</strong> one set of restraints; see text<br/><strong>Duration</strong> 1 hour/level<br/><strong>Saving Throw</strong> Reflex negates; see text; <strong>Spell Resistance</strong> no</p><p>You summon a set of Small or Medium masterwork restraints into being. When you cast this spell, you can choose whether the restraints are manacles or fetters (manacles specifically designed to fit around the ankles). You also summon the restraints' key to your person; the Disable Device DC to open the locked restraints is equal to 15 + your caster level + the modifier of your primary casting ability score. Typically, the restraints appear in your hands. However, as part of the spell's casting, you can make a melee touch attack against a creature; if you succeed and the creature then fails a Reflex saving throw against the spell's DC, the locked fetters appear clasped on the creature or locked manacles clasp you and the creature together. You can instead have manacles restrain the target's limbs in front of or behind it. If you cast the spell as a full-round action, you can make melee touch attacks against two creatures you can reach. If you succeed at both attacks and both creatures fail their Reflex saving throws, you can cause the set of manacles to bind the targets together.</p>
<p>As you increase in level, the restraints become stronger and you gain more control over them. If you are 6th level or higher, you can make the restraints mithral, or you can summon Tiny or Large restraints. If you are 12th level or higher, you can summon Diminutive or Huge restraints. If you use an emerald worth at least 1,000 gp as a material component while casting this spell, as a standard action once during its duration, you can affect any creature bound by these restraints as per dimensional anchor with a duration of 1 minute per caster level. If you are 18th level or higher and use an emerald worth at least 1,000 gp as a material component while casting this spell, the restraints' hardness increases to 30, they have 60 hit points, and they can't be broken with a successful Strength check. (The emerald must be worth at least 2,000 gp if you also wish to use the dimensional anchor effect described earlier.)</p>
<p>If you cast this spell before the duration of a previous casting has lapsed, you can create a new set of restraints or reset the previous spell's duration. If you used an expensive material component during a previous casting, you must again use a component when creating new restraints or resetting the duration if you wish to maintain the special effect. You do not need to touch these previously created shackles to renew their duration, though you must be on the same plane as the shackles. When this spell ends, the restraints disappear, and any ongoing effects created by the spell end.</p>
</>};
const _shades = {title: "Shades", jsx: <><h2 id="spell-shades-shades">Shades</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 340</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/shadow_subschool">_subschool</Link>) [<Link to="/spelldef/shadow_descriptor">_descriptor</Link>]; <strong>Level</strong> arcanist 9, sorcerer 9, wizard 9<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> see text<br/><strong>Effect</strong> see text<br/><strong>Duration</strong> see text<br/><strong>Saving Throw</strong> Will disbelief (if interacted with); varies; see text; <strong>Spell Resistance</strong> yes; see text</p><p>This spell functions like shadow conjuration, except that it mimics conjuration spells of 8th level or lower. The illusory conjurations created deal four-fifths (80%) damage to nonbelievers, and non-damaging effects are 80% likely to work against nonbelievers.</p>
</>};
const _shadow_anchor = {title: "Shadow Anchor", jsx: <><h2 id="spell-shadow_anchor-shadow-anchor">Shadow Anchor</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 211</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/shadow_subschool">_subschool</Link>) [<Link to="/spelldef/shadow_descriptor">_descriptor</Link>]; <strong>Level</strong> arcanist 2, bard 2, mesmerist 2, psychic 2, red mantis assassin 2, skald 2, sorcerer 2, witch 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> S<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Effect</strong> a shadowy shadow tether<br/><strong>Duration</strong> 1 round/level (d); see text<br/><strong>Saving Throw</strong> Will negates; <strong>Spell Resistance</strong> yes</p><blockquote>
<p><em><Link to="/race/wayang">Wayangs</Link> have access to the following spell.</em></p>
</blockquote>
<p>The target's shadow becomes a flexible tether to its current square. The creature can move up to 5 feet from that square without penalty. Moving farther than 5 feet from the tether point requires the target to make a bull rush combat maneuver check against a CMB of 10 + 1/2 your caster level + your Intelligence modifier (if a witch or wizard) or Charisma modifier (if a bard or sorcerer). The target takes a -1 penalty for every 5 feet of distance between it and its tethered square. Failing this check means the target's move is wasted and it cannot move farther away. If it fails this check by 10 or more, it is pulled 5 feet toward the tether square and is knocked prone. If it beats the check by 10 or more, the spell ends. This spell does not work on creatures that do not cast shadows or reflections. If the target uses a teleportation effect or leaves the current plane, the spell ends.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="spell-shadow_anchor--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Shadow Anchor</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 107</Link><br/>Add your tier to the CMD of the shadow tether. A creature attempting to escape the shadow tether using planar travel or teleportation must succeed at a Will saving throw or be shunted to the Plane of Shadow instead of its intended destination, as if it had cast shadow walk (if the target could not reach the Shadow Plane from its current location using shadow walk, this aspect of the spell has no effect).</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _shadow_barbs = {title: "Shadow Barbs", jsx: <><h2 id="spell-shadow_barbs-shadow-barbs">Shadow Barbs</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_magic">Inner Sea Magic pg. 59</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/shadow_subschool">_subschool</Link>) [<Link to="/spelldef/darkness">darkness</Link>]; <strong>Level</strong> arcanist 4, cleric 4, inquisitor 4, oracle 4, red mantis assassin 4, sorcerer 4, warpriest 4, wizard 4<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a single link from a spiked chain)<br/><strong>Range</strong> 0 ft.<br/><strong>Effect</strong> spiked chain-like shadowy weapon<br/><strong>Duration</strong> 1 round/level<br/><strong>Saving Throw</strong> Will negates (see text); <strong>Spell Resistance</strong> no</p><p>This spell, developed originally by priests of Zon-Kuthon in Nidal's early years, has recently crossed the boundary between divine and arcane magic. Although it still bears some of the stigma of being associated with the Midnight Lord, it's rapidly becoming a favorite spell of magi and other martially minded arcane spellcasters.</p>
<p>When you cast this spell, you create a shadowy spiked chain that shimmers and pulses with darkness. The chain exists as long as you carry it; if you ever drop the chain, give it to another, or are disarmed, it immediately vanishes and the spell's duration ends.</p>
<p>The chain radiates darkness in a 10-foot-radius spread around you, reducing the illumination level in this area by one step, but not below the level of dim light.</p>
<p>You can wield the shadow barbs as a spiked chain as if you were fully proficient with spiked chains. Any additional abilities or feats that you possess that apply to spiked chains apply to the shadow barbs as well. The weapon functions as a +2 <Link to="/magic-enh/vicious">vicious</Link> <Link to="/eq-weapon/spiked_chain">spiked chain</Link>. Its enhancement bonus increases to +3 at caster level 11th, to +4 at caster level 15th, and finally to +5 at caster level 19th. When the spell effect ends, you can make a Will save against the spell - if successful, all of the damage caused to you by the shadow barbs' vicious weapon quality vanishes, unless you are dead or unconscious at the time the spell ends, in which case you automatically fail this Will save and the vicious weapon damage remains.</p>
</>};
const _shadow_body = {title: "Shadow Body", jsx: <><h2 id="spell-shadow_body-shadow-body">Shadow Body</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 186</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link> (<Link to="/spelldef/polymorph">polymorph</Link>); <strong>Level</strong> arcanist 7, sorcerer 7, spiritualist 5, witch 7, wizard 7<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 minute/level (D)</p><p>You exchange the crude matter of your material body with the insubstantial essence of the Plane of Shadow, becoming a living shadow yourself. You are visible as an unattached shadow in bright light or normal light, but you gain total <Link to="/rule/concealment">concealment</Link> in dim light or darkness. Against creatures with darkvision, you gain concealment rather than total concealment. Your shadow body is incorporeal for most purposes, though you can't fly or pass through solid objects or creatures. However, you can move at your normal speed along any surface, including horizontal and vertical surfaces and liquids, and you are never slowed by difficult terrain. Your size doesn't change.</p>
<p>You can speak and cast spells and perform mental actions, but you have no physical substance and cannot manipulate objects or attack physically. You can deliver touch spells and effects as if making an incorporeal touch attack. Your equipment merges with your shadow body, so you can't cast spells with a material component unless those spells are prepared with <Link to="/feat/eschew_materials">Eschew Materials</Link>.</p>
</>};
const _shadow_bomb_admixture = {title: "Shadow Bomb Admixture", jsx: <><h2 id="spell-shadow_bomb_admixture-shadow-bomb-admixture">Shadow Bomb Admixture</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 243</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/creation">creation</Link>); <strong>Level</strong> alchemist 2, investigator 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 round/level<br/><strong>Saving Throw</strong> special, see below; <strong>Spell Resistance</strong> special, see below</p><p>Upon drinking an extract created with this formula, you make a significant change to your magical reserve that modifies the nature of all bombs you create and throw during this extract's duration. This effect on your magical reserve has no effect on any discoveries that you use to modify your bombs, but you can only have one admixture effect (formula with the word "bomb admixture" in its title) active at a time. If you drink another bomb admixture, the effects of the former bomb admixture end and the new one becomes active.</p>
<p>When you throw a bomb and hit a direct target, a shadowy substance is released from the bomb covering the direct target and up to three creatures that take damage from the bomb's splash (alchemist's choice). The affected creatures must successfully make a Fortitude saving throw, or they gain <Link to="/rule/concealment">concealment</Link> but treat all other creatures as having concealment for the duration of the shadow bomb admixture. This effect does not ignore spell resistance.</p>
</>};
const _shadow_claws = {title: "Shadow Claws", jsx: <><h2 id="spell-shadow_claws-shadow-claws">Shadow Claws</h2>
<p><strong>Sources</strong> <Link to="/source/villain_codex">Villain Codex pg. 81</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/shadow_subschool">_subschool</Link>) [<Link to="/spelldef/shadow_descriptor">_descriptor</Link>]; <strong>Level</strong> antipaladin 1, arcanist 2, bloodrager 2, bard 2, magus 2, skald 2, sorcerer 2, spiritualist 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 minute/level</p><p>You summon a pair of claws over your hands formed from semi-real material. This grants you two primary claw attacks dealing 1d4 points of damage if you are Medium (1d3 if Small) plus 1 point of Strength damage. A successful Fortitude saving throw negates the Strength damage (DC = this spell's DC).</p>
</>};
const _shadow_conjuration = {title: "Shadow Conjuration", jsx: <><h2 id="spell-shadow_conjuration-shadow-conjuration">Shadow Conjuration</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 340</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/shadow_subschool">_subschool</Link>) [<Link to="/spelldef/shadow_descriptor">_descriptor</Link>]; <strong>Level</strong> arcanist 4, bard 4, mesmerist 4, red mantis assassin 4, skald 4, sorcerer 4, spiritualist 4, wizard 4<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> see text<br/><strong>Effect</strong> see text<br/><strong>Duration</strong> see text<br/><strong>Saving Throw</strong> Will disbelief (if interacted with); varies; see text; <strong>Spell Resistance</strong> yes; see text</p><p>You use material from the Plane of Shadow to shape quasi-real illusions of one or more creatures, objects, or forces. Shadow conjuration can mimic any sorcerer or wizard conjuration (summoning) or conjuration (creation) spell of 3rd level or lower.</p>
<p>Shadow conjurations are only one-fifth (20%) as strong as the real things, though creatures who believe the shadow conjurations to be real are affected by them at full strength. Any creature that interacts with the spell can make a Will save to recognize its true nature.</p>
<p>Spells that deal damage have normal effects unless the affected creature succeeds on a Will save. Each disbelieving creature takes only one-fifth (20%) damage from the attack. If the disbelieved attack has a special effect other than damage, that effect is only 20% likely to occur. Regardless of the result of the save to disbelieve, an affected creature is also allowed any save that the spell being simulated allows, but the save DC is set according to shadow conjuration's level (4th) rather than the spell's normal level. In addition, any effect created by shadow conjuration allows spell resistance, even if the spell it is simulating does not. Shadow objects or substances have normal effects except against those who disbelieve them. Against disbelievers, they are 20% likely to work.</p>
<p>A shadow creature has one-fifth the hit points of a normal creature of its kind (regardless of whether it's recognized as shadowy). It deals normal damage and has all normal abilities and weaknesses. Against a creature that recognizes it as a shadow creature, however, the shadow creature's damage is one-fifth (20%) normal, and all special abilities that do not deal lethal damage are only 20% likely to work. (Roll for each use and each affected character separately.) Furthermore, the shadow creature's AC bonuses are just one-fifth as large.</p>
<p>A creature that succeeds on its save sees the shadow conjurations as transparent images superimposed on vague, shadowy forms. Objects automatically succeed on their Will saves against this spell.</p>
<h3 id="spell-shadow_conjuration-greater-shadow-conjuration">Greater Shadow Conjuration</h3>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 340</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/shadow_subschool">_subschool</Link>) [<Link to="/spelldef/shadow_descriptor">_descriptor</Link>]; <strong>Level</strong> arcanist 7, sorcerer 7, wizard 7<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> see text<br/><strong>Effect</strong> see text<br/><strong>Duration</strong> see text<br/><strong>Saving Throw</strong> Will disbelief (if interacted with); varies; see text; <strong>Spell Resistance</strong> yes; see text</p><p>This spell functions like shadow conjuration, except that it duplicates any sorcerer or wizard conjuration (summoning) or conjuration (creation) spell of 6th level or lower. The illusory conjurations created deal three-fifths (60%) damage to nonbelievers, and non-damaging effects are 60% likely to work against nonbelievers.</p>
</>};
const _shadow_dragon_aspect = {title: "Shadow Dragon Aspect", jsx: <><h2 id="spell-shadow_dragon_aspect-shadow-dragon-aspect">Shadow Dragon Aspect</h2>
<p><strong>Sources</strong> <Link to="/source/kobolds_of_golarion">Kobolds of Golarion pg. 27</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/shadow_subschool">_subschool</Link>) [<Link to="/spelldef/shadow_descriptor">_descriptor</Link>]; <strong>Level</strong> arcanist 4, bard 4, red mantis assassin 4, skald 4, sorcerer 4, wizard 4<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 round/level<br/><strong>Saving Throw</strong> Will disbelief (if interacted with), see text; <strong>Spell Resistance</strong> yes, see text</p><p>You wreathe yourself in the quasi-real form of a dragon. You gain two claw attacks (1d6 plus caster level slashing damage) and a bite attack (1d8 plus caster level piercing damage). These are primary attacks. In addition, you gain shadowy wings, granting you a fly speed equal to your base speed (good maneuverability). Your shadowy natural weapons are only half as strong as the real things, though creatures that believe them to be real are affected at full strength. A creature is permitted one Will save the first time you strike it. If it succeeds, the creature takes half damage from such attacks for the duration of the spell. If you overcome a creature's spell resistance on your first attack, that creature remains vulnerable for the spell's duration; otherwise, it's immune.</p>
</>};
const _shadow_enchantment = {title: "Shadow Enchantment", jsx: <><h2 id="spell-shadow_enchantment-shadow-enchantment">Shadow Enchantment</h2>
<p><strong>Sources</strong> <Link to="/source/occult_realms">Occult Realms pg. 17</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/shadow_subschool">_subschool</Link>) [<Link to="/spelldef/shadow_descriptor">_descriptor</Link>]; <strong>Level</strong> arcanist 3, bard 3, skald 3, sorcerer 3, wizard 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> see text<br/><strong>Effect</strong> see text<br/><strong>Duration</strong> see text<br/><strong>Saving Throw</strong> Will disbelief, see text; <strong>Spell Resistance</strong> yes</p><p>You use material from the Shadow Plane to cast a quasi-real, illusory version of a psychic, sorcerer, or wizard enchantment spell of 2nd level or lower. Spells that deal damage or have other effects work as normal unless the affected creature succeeds at a Will save. If the disbelieved enchantment spell has a damaging effect, that effect is one-fifth as strong (if applicable) or only 20% likely to occur. If recognized as a shadow enchantment, a damaging spell deals only one-fifth (20%) the normal amount of damage.</p>
<p>If the disbelieved attack has a special effect other than damage, that effect is one-fifth as strong (if applicable) or only 20% likely to occur. Regardless of the result of the save to disbelieve, an affected creature is also allowed any save (or spell resistance) that the spell being simulated allows, but the save DC is set according to shadow enchantment's level (3rd) rather than the spell's normal level. Objects, mindless creatures, and creatures immune to mind-affecting effects automatically succeed at their Will saves against this spell.</p>
<h3 id="spell-shadow_enchantment-greater-shadow-enchantment">Greater Shadow Enchantment</h3>
<p><strong>Sources</strong> <Link to="/source/occult_realms">Occult Realms pg. 17</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/shadow_subschool">_subschool</Link>) [<Link to="/spelldef/shadow_descriptor">_descriptor</Link>]; <strong>Level</strong> arcanist 6, bard 6, skald 6, sorcerer 6, wizard 6<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> see text<br/><strong>Effect</strong> see text<br/><strong>Duration</strong> see text<br/><strong>Saving Throw</strong> Will disbelief, see text; <strong>Spell Resistance</strong> yes</p><p>This spell functions like shadow enchantment, except that it enables you to create partially real, illusory versions of psychic, sorcerer, or wizard enchantment spells of 5th level or lower. If the spell is recognized as a greater shadow enchantment, it's only three-fifths (60%) as effective.</p>
</>};
const _shadow_endurance = {title: "Shadow Endurance", jsx: <><h2 id="spell-shadow_endurance-shadow-endurance">Shadow Endurance</h2>
<p><strong>Sources</strong> <Link to="/source/agents_of_evil">Agents of Evil pg. 31</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/shadow_subschool">_subschool</Link>) [<Link to="/spelldef/shadow_descriptor">_descriptor</Link>]; <strong>Level</strong> arcanist 6, bard 5, mesmerist 5, shaman 5, skald 5, sorcerer 6, spiritualist 5, wizard 6<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a fetchling's tooth)<br/><strong>Range</strong> personal<br/><strong>Effect</strong> see text<br/><strong>Duration</strong> 1 hour/level until discharged, then 1 minute/level; see text<br/><strong>Saving Throw</strong> Will disbelief (if interacted with), varies, see text; <strong>Spell Resistance</strong> see text</p><p>You conjure protective wisps of darkness made from shadow. If you are reduced below 0 hit points or rendered unconscious, shadow endurance immediately discharges, shunting your injured body into a hidden alcove on the Shadow Plane. You immediately stabilize, but cannot awaken or take any further actions until the second duration expires.</p>
<p>As you vanish, a quasi-real duplicate of you made from shadow substance appears where you fell, as if created by shadow conjuration. The duplicate acts on your initiative and is under your control. Your duplicate is 1/4 as real as you and appears with 25% of your full hit point total, and any creature that fails a Will saving throw believes it to be you. The duplicate has the same equipment-based bonuses as you, but deals only 1/4 of your normal damage against enemies. It can cast any spells you can, drawing on your reserve of magic, but the duplicate's caster level is 1/4 your actual level. Regardless of your alignment, your shadow duplicate is neutral evil, though it will not harm your friends and allies.</p>
<p>When the second duration of the spell expires, your duplicate disappears and your body reappears in the location from which you vanished. If the image is destroyed, the spell immediately expires and your body reappears.</p>
</>};
const _shadow_evocation = {title: "Shadow Evocation", jsx: <><h2 id="spell-shadow_evocation-shadow-evocation">Shadow Evocation</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 340</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/shadow_subschool">_subschool</Link>) [<Link to="/spelldef/shadow_descriptor">_descriptor</Link>]; <strong>Level</strong> arcanist 5, bard 5, mesmerist 5, skald 5, sorcerer 5, spiritualist 5, wizard 5<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> see text<br/><strong>Effect</strong> see text<br/><strong>Duration</strong> see text<br/><strong>Saving Throw</strong> Will disbelief (if interacted with); <strong>Spell Resistance</strong> yes</p><p>You tap energy from the Plane of Shadow to cast a quasi-real, illusory version of a sorcerer or wizard evocation spell of 4th level or lower. Spells that deal damage have normal effects unless an affected creature succeeds on a Will save. Each disbelieving creature takes only one-fifth damage from the attack. If the disbelieved attack has a special effect other than damage, that effect is one-fifth as strong (if applicable) or only 20% likely to occur. If recognized as a shadow evocation, a damaging spell deals only one-fifth (20%) damage. Regardless of the result of the save to disbelieve, an affected creature is also allowed any save (or spell resistance) that the spell being simulated allows, but the save DC is set according to shadow evocation's level (5th) rather than the spell's normal level.</p>
<p>Non-damaging effects have normal effects except against those who disbelieve them. Against disbelievers, they have no effect.</p>
<p>Objects automatically succeed on their Will saves against this spell.</p>
<h3 id="spell-shadow_evocation-greater-shadow-evocation">Greater Shadow Evocation</h3>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 340</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/shadow_subschool">_subschool</Link>) [<Link to="/spelldef/shadow_descriptor">_descriptor</Link>]; <strong>Level</strong> arcanist 8, sorcerer 8, wizard 8<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> see text<br/><strong>Effect</strong> see text<br/><strong>Duration</strong> see text<br/><strong>Saving Throw</strong> Will disbelief (if interacted with); <strong>Spell Resistance</strong> yes</p><p>This spell functions like shadow evocation, except that it enables you to create partially real, illusory versions of sorcerer or wizard evocation spells of 7th level or lower. If recognized as a greater shadow evocation, a damaging spell deals only three-fifths (60%) damage.</p>
</>};
const _shadow_invasion = {title: "Shadow Invasion", jsx: <><h2 id="spell-shadow_invasion-shadow-invasion">Shadow Invasion</h2>
<p><strong>Sources</strong> <Link to="/source/planar_adventures">Planar Adventures pg. 44</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/summoning">summoning</Link>); <strong>Level</strong> arcanist 4, magus 4, sorcerer 4, summoner 4, unchained summoner 4, wizard 4<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, F (a masterwork piercing or slashing weapon)<br/><strong>Range</strong> 30 ft.<br/><strong>Area</strong> 30-ft. radius emanation centered on you<br/><strong>Duration</strong> 1 round/level (d); see text<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>Using a slashing motion with the spell's focus as part of the casting of shadow invasion, you cut open a rift to the Plane of Shadow that fills a 30-foot area with shadowy energies. This area is stationary and becomes dark and gloomy, reducing the light level by one step (as darkness). Certain spells are enhanced within the area; spells of the shadow subschool that have reduced effects when disbelieved (such as shadow evocation) have their reduced effects increased by 20% (to a maximum of 90%) when determining their effects on targets within the area of shadow invasion.</p>
<p>In addition, the rift created by shadow invasion has a chance of attracting attention from the other side, and the spell can be inverted to bring these watchers through. When shadow invasion is dismissed as a standard action, there is a chance that a single evangelist kyton will be summoned under the caster's command (as per <Link to="/spell/summon_monster_v">summon monster V</Link>). This chance is 5% for every full round that shadow invasion was active. If the caster level of shadow invasion is 16th or greater, this effect summons an interlocutor kyton instead. A kyton summoned this way remains for a number of rounds equal to what the remaining duration of shadow invasion would have been had it not been dismissed. Successfully summoning a kyton this way is a lawful and evil act, as though casting a spell with the lawful and evil descriptors.</p>
</>};
const _shadow_jaunt = {title: "Shadow Jaunt", jsx: <><h2 id="spell-shadow_jaunt-shadow-jaunt">Shadow Jaunt</h2>
<p><strong>Sources</strong> <Link to="/source/villain_codex">Villain Codex pg. 81</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/shadow_subschool">_subschool</Link>) [<Link to="/spelldef/shadow_descriptor">_descriptor</Link>]; <strong>Level</strong> antipaladin 3, arcanist 4, bard 4, skald 4, sorcerer 4, spiritualist 4, summoner 4, unchained summoner 4, wizard 4<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> you<br/><strong>Duration</strong> instantaneous and 1 round; see text</p><p>You instantly travel between shadows to a point within range, though line of sight is not necessary. You leave a shadowy image of yourself in your former location and are wrapped in shadow at your destination; you can attempt a Stealth check as a free action to hide in your new location. Creatures that fail opposed Perception checks typically aren't aware that you are no longer at your former location unless they are familiar with this spell and identify the effects. Any attack on your former location causes the shadows to disperse, allowing any creature that can see your former location to immediately notice your disappearance. In addition, for 1 round, the envelope of shadow around you grants you concealment (20% miss chance). This spell doesn't function if there are no shadows within 5 feet of your starting location, and you can't travel through your own shadow. If you choose a destination that has no shadows, you appear from the shadow closest to your destination that's within the spell's range (this could be your starting location if there are no other shadows within the spell's range).</p>
</>};
const _shadow_of_doubt = {title: "Shadow of Doubt", jsx: <><h2 id="spell-shadow_of_doubt-shadow-of-doubt">Shadow of Doubt</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_races">Inner Sea Races pg. 222</Link><br/><strong>School</strong> <Link to="/spelldef/enchantment">enchantment</Link> (<Link to="/spelldef/compulsion">compulsion</Link>) [<Link to="/spelldef/darkness">darkness</Link>, <Link to="/spelldef/emotion">emotion</Link>, <Link to="/spelldef/evil">evil</Link>, <Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> antipaladin 4, bard 4, skald 4<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Targets</strong> one creature/3 levels<br/><strong>Duration</strong> 1 round/level<br/><strong>Saving Throw</strong> Will partial (see text); <strong>Spell Resistance</strong> yes</p><blockquote>
<p><em>The following spell is available to the indicated race or ethnicity: <Link to="/race/tiefling">Tiefling</Link></em></p>
</blockquote>
<p>You create a shadowy aura of doubt fueled by a foe's own inner flaws. Targets perceive all illumination as if it were one light level darker, to a minimum light level of darkness (not supernatural darkness), even on a successful saving throw.</p>
<p>Fleeting mental shadows of regrets and anxieties distract the spell's targets; at the start of each of their turns, they must each succeed at a Will save or be staggered for 1 round. A good-aligned target takes a -4 penalty on saving throws against this effect; an evil-aligned target gains a +4 bonus instead.</p>
</>};
const _shadow_projection = {title: "Shadow Projection", jsx: <><h2 id="spell-shadow_projection-shadow-projection">Shadow Projection</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 243</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link> [<Link to="/spelldef/evil">evil</Link>]; <strong>Level</strong> arcanist 4, sorcerer 4, wizard 4<br/><strong>Casting Time</strong> 1 minute<br/><strong>Components</strong> S<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 hour/level (D)</p><p>With this spell, you infuse your life force and psyche into your shadow, giving it independent life and movement as if it were an undead <Link to="/monster/shadow">shadow</Link>. Your physical body lies comatose while you are projecting your shadow, and your body has no shadow or reflection while the spell is in effect.</p>
<p>While projecting your shadow, you gain a shadow's darkvision, defensive abilities, fly speed, racial stealth modifier, and strength damage attack. You do not gain the creature's create spawn ability, nor its skill ranks or Hit Dice. Your shadow has Hit Dice and hit points equal to your own. Your shadow projection has the undead type and may be turned or affected as undead.</p>
<p>If your shadow projection is slain, you return to your physical body and are immediately reduced to -1 hit points. Your condition becomes dying, and you must begin making Constitution checks to stabilize.</p>
</>};
const _shadow_step = {title: "Shadow Step", jsx: <><h2 id="spell-shadow_step-shadow-step">Shadow Step</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 237</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/shadow_subschool">_subschool</Link>) [<Link to="/spelldef/shadow_descriptor">_descriptor</Link>]; <strong>Level</strong> arcanist 4, bard 4, psychic 4, red mantis assassin 4, skald 4, sorcerer 4, spiritualist 4, witch 4, wizard 4<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Target</strong> you<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>To use this spell, you must be in an area of dim light or darkness. You enter a shadow or area of darkness, which transports you along a coiling path of shadowstuff to another dim or dark location within range.</p>
</>};
const _shadow_transmutation = {title: "Shadow Transmutation", jsx: <><h2 id="spell-shadow_transmutation-shadow-transmutation">Shadow Transmutation</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_shadows">Blood of Shadows pg. 30</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/shadow_subschool">_subschool</Link>) [<Link to="/spelldef/shadow_descriptor">_descriptor</Link>]; <strong>Level</strong> arcanist 6, bard 6, medium 6, shaman 6, skald 6, sorcerer 6, spiritualist 6, summoner 6, witch 6, wizard 6<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> see text<br/><strong>Target</strong> see text<br/><strong>Duration</strong> see text<br/><strong>Saving Throw</strong> Will disbelief (if interacted with), varies, see text; <strong>Spell Resistance</strong> yes, see text</p><p>You suffuse one subject's body with energy from the Shadow Plane, altering its form to match a creature from the Shadow Plane. Shadow transmutation can mimic any of the following spells: animal growth, anthropomorphic animal, enlarge person, fins to feet, longarm, polymorph, reduce person, and stone fist. If using shadow transmutation as polymorph, the target does not gain any sensory abilities that its new form has (such as low-light vision or darkvision) and the speed of any movement types gained from the spell cannot exceed the target's base speed or natural speed with those movement types (whichever is higher). A creature under the effects of shadow transmutation deals normal damage and has all the normal abilities and weaknesses of whatever form it assumes using the spell.</p>
<p>Any creature that interacts with a target under the effects of the spell (including attacking or being attacked by that creature) can attempt a Will save to recognize the target's true nature. Creatures that succeed at their Will saves to disbelieve the illusion take one-fifth (20%) of the normal damage from the target's natural attacks or special abilities granted by the target's shadowy form (if any), and the target's special abilities that don't deal damage have only a 20% chance of working against them. Creatures that succeed at their saves see the shadow transmutation as transparent images superimposed over the target.</p>
<h3 id="spell-shadow_transmutation-greater-shadow-transmutation">Greater Shadow Transmutation</h3>
<p><strong>Sources</strong> <Link to="/source/blood_of_shadows">Blood of Shadows pg. 31</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/shadow_subschool">_subschool</Link>) [<Link to="/spelldef/shadow_descriptor">_descriptor</Link>]; <strong>Level</strong> arcanist 9, shaman 9, sorcerer 9, witch 9, wizard 9<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> see text<br/><strong>Target</strong> see text<br/><strong>Duration</strong> see text<br/><strong>Saving Throw</strong> Will disbelief (if interacted with), varies, see text; <strong>Spell Resistance</strong> yes, see text</p><p>This spell functions like shadow transmutation, except it can mimic greater polymorph instead of polymorph. The illusory attacks and special abilities of any shape assumed using greater shadow transmutation deal three-fifths (60%) damage to nonbelievers, and non-damaging effects are 60% likely to work against nonbelievers.</p>
</>};
const _shadow_trap = {title: "Shadow Trap", jsx: <><h2 id="spell-shadow_trap-shadow-trap">Shadow Trap</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_shadows">Blood of Shadows pg. 31</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/shadow_subschool">_subschool</Link>); <strong>Level</strong> antipaladin 1, arcanist 1, bloodrager 1, bard 1, cleric 1, mesmerist 1, occultist 1, oracle 1, psychic 1, shaman 1, skald 1, sorcerer 1, warpriest 1, witch 1, wizard 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one creature<br/><strong>Duration</strong> 1 round/level (D)<br/><strong>Saving Throw</strong> Will negates; <strong>Spell Resistance</strong> yes</p><p>You pin the target's shadow to its current location, causing the target to become entangled and preventing it from moving farther than 5 feet from its original position, as if its shadow were anchored to the terrain. Each round on its turn, the target can attempt a new saving throw to end the effect as a full-round action. A flying creature can only hover in place or fall while entangled in this manner. This spell automatically fails when cast on a creature that doesn't throw a shadow, and it ends if the creature is entirely in an area with no illumination.</p>
</>};
const _shadow_walk = {title: "Shadow Walk", jsx: <><h2 id="spell-shadow_walk-shadow-walk">Shadow Walk</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 341</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/shadow_subschool">_subschool</Link>) [<Link to="/spelldef/shadow_descriptor">_descriptor</Link>]; <strong>Level</strong> alchemist 6, arcanist 6, bard 5, investigator 6, mesmerist 5, skald 5, sorcerer 6, spiritualist 6, wizard 6<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> touch<br/><strong>Targets</strong> up to one touched creature/level<br/><strong>Duration</strong> 1 hour/level (D)<br/><strong>Saving Throw</strong> Will negates; <strong>Spell Resistance</strong> yes</p><p>To use the shadow walk spell, you must be in an area of dim light. You and any creature you touch are then transported along a coiling path of shadowstuff to the edge of the Material Plane where it borders the Plane of Shadow. The effect is largely illusory, but the path is quasi-real. You can take more than one creature along with you (subject to your level limit), but all must be touching each other.</p>
<p>In the region of shadow, you move at a rate of 50 miles per hour, moving normally on the borders of the Plane of Shadow but much more rapidly relative to the Material Plane. Thus, you can use this spell to travel rapidly by stepping onto the Plane of Shadow, moving the desired distance, and then stepping back onto the Material Plane.</p>
<p>Because of the blurring of reality between the Plane of Shadow and the Material Plane, you can't make out details of the terrain or areas you pass over during transit, nor can you predict perfectly where your travel will end. It's impossible to judge distances accurately, making the spell virtually useless for scouting or spying. Furthermore, when the spell effect ends, you are shunted 1d10 &times; 100 feet in a random horizontal direction from your desired endpoint. If this would place you within a solid object, you are shunted 1d10 &times; 1,000 feet in the same direction. If this would still place you within a solid object, you (and any creatures with you) are shunted to the nearest empty space available, but the strain of this activity renders each creature fatigued (no save).</p>
<p>Shadow walk can also be used to travel to other planes that border on the Plane of Shadow, but this usage requires the transit of the Plane of Shadow to arrive at a border with another plane of reality. The transit of the Plane of Shadow requires 1d4 hours.</p>
<p>Any creatures touched by you when shadow walk is cast also make the transition to the borders of the Plane of Shadow.</p>
<p>They may opt to follow you, wander off through the plane, or stumble back into the Material Plane (50% chance for either of the latter results if they are lost or abandoned by you). Creatures unwilling to accompany you into the Plane of Shadow receive a Will saving throw, negating the effect if successful.</p>
</>};
const _shadow_weapon = {title: "Shadow Weapon", jsx: <><h2 id="spell-shadow_weapon-shadow-weapon">Shadow Weapon</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 237</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/shadow_subschool">_subschool</Link>) [<Link to="/spelldef/shadow_descriptor">_descriptor</Link>]; <strong>Level</strong> arcanist 1, bloodrager 1, occultist 1, psychic 1, red mantis assassin 1, sorcerer 1, witch 1, wizard 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> 0 ft.<br/><strong>Effect</strong> one shadow weapon<br/><strong>Duration</strong> 1 minute/level<br/><strong>Saving Throw</strong> Will disbelief (if interacted with); <strong>Spell Resistance</strong> yes</p><p>Drawing upon the Plane of Shadow, you shape a quasi-real masterwork melee weapon of a type you are proficient with. You may use this weapon to make attacks as if it were a real weapon, dealing normal damage for a weapon of its type. The first time you hit a creature with the weapon, it may make a Will save to disbelieve; failure means the weapon deals damage normally, success means it only takes 1 point of damage from the weapon's attacks. The weapon only deals 1 point of damage to objects.</p>
<p>If an attacked creature has spell resistance, you make a caster level check (1d20 + caster level) against that spell resistance the first time the shadow weapon strikes it. If the weapon is successfully resisted, the spell is dispelled. If not, the target may save to disbelieve as normal.</p>
<p>At 5th level, the weapon gains a +1 enhancement bonus. At 10th-level, you may increase the enhancement bonus to +2 or add the frost or keen weapon property. The frost and keen properties have no effect if the target makes its disbelief save.</p>
<p>The spell ends if the weapon leaves your possession.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="spell-shadow_weapon--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Shadow Weapon</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 107</Link><br/>Add your tier to your caster level when determining what enhancement bonus or weapon special abilities the weapon can have. The weapon deals half damage to creatures that disbelieve in it and to objects, instead of only 1 point.</p>
<p>You can spend a swift action to transform the weapon into a dull black metal ring on your finger, or to return it from its ring form to its weapon form in your hand.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _shadowbard = {title: "Shadowbard", jsx: <><h2 id="spell-shadowbard-shadowbard">Shadowbard</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 236</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/shadow_subschool">_subschool</Link>) [<Link to="/spelldef/shadow_descriptor">_descriptor</Link>]; <strong>Level</strong> bard 5, skald 5<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Effect</strong> phantom singer<br/><strong>Duration</strong> 1 round/level (D)<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>You conjure up a quasi-real phantom singer that is visible as a shifting, shadowy duplicate of yourself. The singer follows you automatically, moving as you move even if you teleport. The singer cannot be damaged, but can be dispelled. When a shadowbard comes into being, it immediately begins a bardic performance of your choice - it has access to all of the bardic performances that you do. It continues that bardic performance until you direct it as a move action to switch to a different performance. Rounds spent by a shadowbard creating a bardic performance do not decrease the number of rounds you can use your own bardic performance, nor can a shadowbard's bardic performance be used to trigger spells that require you to begin or cease a bardic performance.</p>
</>};
const _shadowfade = {title: "Shadowfade", jsx: <><h2 id="spell-shadowfade-shadowfade">Shadowfade</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_darklands">Heroes of the Darklands pg. 9</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/shadow_subschool">_subschool</Link>); <strong>Level</strong> arcanist 1, bard 1, inquisitor 1, mesmerist 1, skald 1, sorcerer 1, summoner 1, unchained summoner 1, wizard 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a blindfold)<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> 1 minute/level (D)<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>In areas of darkness, the target of shadowfade is invisible to creatures using darkvision to see. In areas of dim light, the target gains <Link to="/rule/concealment">concealment</Link> against creatures using darkvision. This spell has no effect in areas of normal light or brighter, and is automatically dispelled if the target enters an area of bright light or takes a hostile action.</p>
</>};
const _shadowform = {title: "Shadowform", jsx: <><h2 id="spell-shadowform-shadowform">Shadowform</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_shadows">Blood of Shadows pg. 31</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/shadow_subschool">_subschool</Link>) [<Link to="/spelldef/shadow_descriptor">_descriptor</Link>]; <strong>Level</strong> antipaladin 4, arcanist 4, bard 4, mesmerist 4, psychic 4, skald 4, sorcerer 4, spiritualist 4, witch 4, wizard 4<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> 1 round/level (D)<br/><strong>Saving Throw</strong> Will negates (see text); <strong>Spell Resistance</strong> yes</p><p>You replace the target's body with mystic shadow material drawn from the Shadow Plane, rendering the target's physical form only quasi-real. Whenever a foe tries to directly attack the target of the spell (for instance, with a weapon or a targeted spell), that foe must attempt a Will save to disbelieve. If successful, the opponent can attack the target normally and is unaffected by shadowform for 1 round. If the foe fails, the target takes only one-fifth the normal amount of damage from the foe's successful attack or effect, and if the attack has a special effect other than damage, that effect is one-fifth as strong as normal (if applicable) or only 20% as likely to occur. Objects automatically succeed at their Will saves against this spell.</p>
</>};
const _shadowmind = {title: "Shadowmind", jsx: <><h2 id="spell-shadowmind-shadowmind">Shadowmind</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_shadows">Blood of Shadows pg. 16</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/phantasm">phantasm</Link>); <strong>Level</strong> antipaladin 2, arcanist 3, cleric 3, druid 3, hunter 3, inquisitor 2, mesmerist 3, occultist 3, oracle 3, psychic 3, shaman 3, sorcerer 3, warpriest 3, witch 2, wizard 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a small square of black silk)<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Target</strong> up to one creature/level, no two of which can be more than 30 ft. apart<br/><strong>Duration</strong> 1 minute/level<br/><strong>Saving Throw</strong> Will negates; <strong>Spell Resistance</strong> yes</p><p>You dim your targets' perceptions of light and shadow, convincing them the space they occupy is dark. Each creature that fails its save perceives the world around it as one light level darker than its true illumination level. The spell does not change the light level outside of the targets' perception, and does not create magical darkness. However, the spell creates an illusion of darkness rather than actual darkness, so low-light and darkvision don't allow a target to see in the conditions created by the spell. Even targets that see normally through magical darkness suffer a loss of vision from this spell.</p>
</>};
const _shadowy_haven = {title: "Shadowy Haven", jsx: <><h2 id="spell-shadowy_haven-shadowy-haven">Shadowy Haven</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 113</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> arcanist 4, psychic 4, red mantis assassin 4, sorcerer 4, wizard 4<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a small black silk bag)<br/><strong>Range</strong> touch<br/><strong>Target</strong> one 5-foot square of floor touched<br/><strong>Duration</strong> 2 hours/level (D)<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><blockquote>
<p><em><Link to="/race/fetchling">Fetchlings</Link> have access to the following spell.</em></p>
</blockquote>
<p>This spell functions like rope trick, except the point of entry is through a 5-foot-square instead of a rope. The space holds as many as 10 creatures of any size.</p>
<p>When this spell is cast upon a 5-foot-square part of a wall, it creates an extradimensional space adjacent to the Plane of Shadow. Creatures in the extradimensional space are hidden beyond the reach of spells (including divinations) unless those spells work across planes. The space holds as many as 10 creatures (of any size). The entrance to the extradimensional space remains visible as an area that is darker than the ambient illumination.</p>
<p>Spells cannot be cast across the extradimensional interface, nor can area effects cross it. Those in the extradimensional space can see out of it as if a 5-foot-by-5-foot door or window were centered on the affected surface. The window is invisible (though it is within the shadowed entrance to the spell, which is visible), and even creatures that can see the window from the outside can't see through it. Anything inside the extradimensional space is ejected when the spell ends. Only one creature may enter or exit the extradimensional space at a time.</p>
<p>The entrance is only open when the area around it is in dim light. Any other level of light (brighter or darker) closes the entrance, trapping creatures inside the extradimensional space. If the entrance is closed when the spell expires, there is a 50% chance that creatures in it are ejected into the Shadow Plane instead of the location of the entrance. If this occurs, the creatures appear on the Shadow Plane 1d10 miles in a random direction from their corresponding location on the Material Plane. The spell has no effect if cast on a plane that is not adjacent to the Shadow Plane.</p>
<p>Because the extradimensional space is adjacent to the Shadow Plane, any shadow walk spell or similar effect that allows travel to the Shadow Plane is more accurate, reducing the distance creatures arrive off-target by half.</p>
</>};
const _shambler = {title: "Shambler", jsx: <><h2 id="spell-shambler-shambler">Shambler</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 341</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/creation">creation</Link>); <strong>Level</strong> druid 9, shaman 9<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Effect</strong> three or more shambling mounds, no two of which can be more than 30 ft. apart; see text<br/><strong>Duration</strong> 7 days or 7 months (d); see text<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>The shambler spell creates 1d4+2 shambling mounds with the advanced template. The creatures willingly aid you in combat or battle, perform a specific mission, or serve as bodyguards. The creatures remain with you for 7 days unless you dismiss them. If the shamblers are created only for guard duty, however, the duration of the spell is 7 months. In this case, the shamblers can only be ordered to guard a specific site or location. Shamblers summoned to guard duty cannot move outside the spell's range, which is measured from the point where each first appeared. You can only have one shambler spell in effect at one time. If you cast this spell while another casting is still in effect, the previous casting is dispelled. The shamblers have resistance to fire as normal shambling mounds do only if the terrain where they are summoned is rainy, marshy, or damp.</p>
</>};
const _shamefully_overdressed = {title: "Shamefully Overdressed", jsx: <><h2 id="spell-shamefully_overdressed-shamefully-overdressed">Shamefully Overdressed</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_intrigue">Ultimate Intrigue pg. 225</Link><br/><strong>School</strong> <Link to="/spelldef/enchantment">enchantment</Link> (<Link to="/spelldef/compulsion">compulsion</Link>) [<Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> bard 2, inquisitor 2, mesmerist 2, psychic 3, skald 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> 1 round/level (D)<br/><strong>Saving Throw</strong> Will negates; <strong>Spell Resistance</strong> yes</p><p>The target sees its own attire as hopelessly out of fashion, ostentatious, and embarrassing, and is filled with a compulsion to strip off all clothing. Each round, the target must spend a move action to remove a worn item that can be removed with a move action, dropping the item once it is removed. The target doesn't distinguish between magical and nonmagical items when removing them. Each round it removes an item as determined randomly from the following slots: belt, body, chest, eyes, feet, hands, head, headband, shoulders, or wrists. When determining randomly, don't include any slots if the character has no item of that sort, and don't include items that take more than one move action to remove. Though creatures can't have more than one magic item in any of those slots, they can have multiple mundane items that fit each slot, in which case randomly decide which one they remove. If a target is wearing clothing that doesn't fit in any of those slots, such as breeches or a quiver, add it to the list of possibilities at the GM's discretion.</p>
<p>The target regards the discarded items with revulsion, and if forced to touch such an item (such as with a melee or ranged touch attack using the item as an improvised weapon), the target becomes sickened for 1d3 rounds. Other than the move action to remove items, the character can take whatever actions it chooses.</p>
</>};
const _straitjacket = {title: "Straitjacket", jsx: <><h2 id="spell-straitjacket-straitjacket">Straitjacket</h2>
<p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 128</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/creation">creation</Link>); <strong>Level</strong> arcanist 5, inquisitor 4, occultist 4, sorcerer 5, summoner 5, unchained summoner 5, wizard 5<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (leather strap)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one creature<br/><strong>Duration</strong> 1 round/level (D)<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> yes</p><p>You cause a straitjacket to spring into existence to restrain the target creature. You attempt a combat maneuver against the target's CMD. Your CMB for this check is equal to your caster level + 5 due to the straightjacket's Strength. This combat maneuver doesn't provoke an attack of opportunity, and if it succeeds, the target is restrained. This is similar to the grappled condition, except the target is able to move at its normal speed, the restraint doesn't cause the target to require concentration checks to use abilities that require concentration, and the target can't take actions that require one or more hands or arms to perform (including casting spells that require a somatic or material component).</p>
<p>Once it has been restrained for 1 round, the target can attempt an additional saving throw against a magical effect that makes it confused, a curse, a fear effect, or a madness. The caster chooses which effect the target gets an extra save against. This extra save applies to only effects with durations of 10 minutes per level or less, and it doesn't apply to instantaneous effects. This extra save occurs only once per casting of straitjacket.</p>
<p>A creature can attempt to escape the straitjacket with a combat maneuver check or Escape Artist check, with a DC equal to 10 + your caster level + your Intelligence, Wisdom, or Charisma modifier, whichever is highest.</p>
</>};
const _strand_of_the_tangled_knot = {title: "Strand of the Tangled Knot", jsx: <><h2 id="spell-strand_of_the_tangled_knot-strand-of-the-tangled-knot">Strand of the Tangled Knot</h2>
<p><strong>Sources</strong> <Link to="/source/legacy_of_the_first_world">Legacy of the First World pg. 17</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link>; <strong>Level</strong> cleric 1, inquisitor 1, oracle 1, shaman 1, warpriest 1, witch 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M/DF (a small knot of twin)<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 round/level (D)</p><p>You mimic tugging at the Green Mother's legendary Tangled Knot to subtly alter your fate. The next single attack made against you takes a -10 penalty. If that attack is a critical hit, it is instead treated as a normal hit.</p>
</>};
const _strangling_hair = {title: "Strangling Hair", jsx: <><h2 id="spell-strangling_hair-strangling-hair">Strangling Hair</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 240</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> arcanist 3, psychic 3, red mantis assassin 3, sorcerer 3, witch 3, wizard 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one creature<br/><strong>Duration</strong> concentration, up to 1 round/level<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> yes</p><p>Your hair animates and extends to grapple and constrict an opponent. Make a grapple check against the target using your caster level as the base attack bonus plus a bonus equal to your Intelligence bonus (if a witch or wizard) or Charisma bonus (if a sorcerer). This grapple check does not provoke attacks of opportunity. If your hair succeeds in grappling a foe, that creature takes 1d6 points of damage or your unarmed strike damage, whichever is greater, and gains the grappled condition. Your hair receives a +5 bonus on grapple checks made against opponents it is already grappling, but cannot move foes or pin foes. Each round that your hair succeeds on a grapple check, it deals an additional 1d6 points of damage. The CMD of your hair, for the purposes of escaping the grapple, is equal to 10 + its CMB.</p>
<p>Once you choose a target, your hair continues to attack that target independently of your own actions. You may designate a new target as a move action, which causes your hair to release its current target (if any) and attack the new target that round. Your hair cannot be targeted as a separate creature, but it can be dispelled.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="spell-strangling_hair--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Strangling Hair</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 109</Link><br/>You may use your hair to attempt dirty trick, disarm, steal, or trip combat maneuvers instead of grapple combat maneuvers. Add your tier to combat maneuver checks attempted with your hair and to your hair's damage rolls made as part of a grapple.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _stricken_heart = {title: "Stricken Heart", jsx: <><h2 id="spell-stricken_heart-stricken-heart">Stricken Heart</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 194</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link> [<Link to="/spelldef/death">death</Link>]; <strong>Level</strong> arcanist 2, inquisitor 2, mesmerist 2, psychic 2, shaman 3, sorcerer 2, spiritualist 2, witch 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> yes</p><p>This spell covers your hand with a writhing black aura. As part of casting the spell, you can make a melee touch attack that deals 2d6 points of negative energy damage and causes the target to be staggered for 1 round. If the attack is a critical hit, the target is staggered for 1 minute instead. Creatures immune to precision damage are immune to the staggered effect.</p>
</>};
const _strip_scales = {title: "Strip Scales", jsx: <><h2 id="spell-strip_scales-strip-scales">Strip Scales</h2>
<p><strong>Sources</strong> <Link to="/source/kobolds_of_golarion">Kobolds of Golarion pg. 27</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> arcanist 5, druid 4, hunter 4, sorcerer 5, witch 5, wizard 5<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M/DF (a single reptile scale)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one living creature<br/><strong>Duration</strong> 1 minute/level<br/><strong>Saving Throw</strong> Fortitude; <strong>Spell Resistance</strong> yes</p><p>You reduce the target's racial natural armor bonus by 1 point per 3 caster levels.</p>
</>};
const _strong_jaw = {title: "Strong Jaw", jsx: <><h2 id="spell-strong_jaw-strong-jaw">Strong Jaw</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 247</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> druid 4, hunter 3, ranger 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> 1 minute/level<br/><strong>Saving Throw</strong> Fortitude negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>Laying a hand upon an allied creature's jaw, claws, tentacles, or other natural weapons, you enhance the power of that creature's natural attacks. Each natural attack that creature makes deals damage as if the creature were two sizes larger than it actually is. If the creature is already Gargantuan or Colossal-sized, double the amount of damage dealt by each of its natural attacks instead. This spell does not actually change the creature's size; all of its statistics except the amount of damage dealt by its natural attacks remain unchanged.</p>
</>};
const _strong_wings = {title: "Strong Wings", jsx: <><h2 id="spell-strong_wings-strong-wings">Strong Wings</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 201</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> arcanist 1, bloodrager 1, druid 1, hunter 1, ranger 1, red mantis assassin 1, sorcerer 1, witch 1, wizard 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> 1 minute/level<br/><strong>Saving Throw</strong> Fortitude negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><blockquote>
<p><em><Link to="/race/strix">Strix</Link> have access to the following spell.</em></p>
</blockquote>
<p>The target's wings grow more powerful, causing its fly speed to increase by +10 feet and its maneuverability to improve by one category (to a maximum of good). This increase counts as an enhancement bonus. This spell has no effect on wingless creatures or winged creatures that cannot fly.</p>
</>};
const _stumble_gap = {title: "Stumble Gap", jsx: <><h2 id="spell-stumble_gap-stumble-gap">Stumble Gap</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 247</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/creation">creation</Link>); <strong>Level</strong> arcanist 1, sorcerer 1, wizard 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, F (miniature shovel costing 10 gp)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Effect</strong> see text<br/><strong>Duration</strong> 1 round + 1 round/level<br/><strong>Saving Throw</strong> Reflex partial; <strong>Spell Resistance</strong> no</p><p>You create a shallow extradimensional hole perfectly sized to trip anyone who steps within it. This hole occupies a single 5-foot square with a depth of six inches. Any creature occupying the square when you first create the hole, or who later steps into the square containing the hole, must make a Reflex saving throw to avoid falling prone in an adjacent square and taking 1d6 points of damage. A creature that makes its saving throw still stumbles ever so slightly and takes a -1 penalty on all rolls and checks for 1 round. The spell has no effect on creatures adjacent to the square containing the hole.</p>
</>};
